const MONTH_NAMES_NO = ['Januar','Februar','Mars','April','Mai','Juni','Juli','August','September','Oktober','November','Desember']
const DAY_NAMES_NO = ['Mandag','Tirsdag','Onsdag','Torsdag','Fredag','Lørdag','Søndag']
const DAY_SHORT_NO = ['Ma','Ti','On','To','Fr','Lø','Sø']

function getMonthDays(year, month) {
  const firstDay = new Date(year, month, 1)
  const lastDay = new Date(year, month+1, 0)
  const days = []
  // pad start
  let startDow = firstDay.getDay()===0?6:firstDay.getDay()-1
  for (let i=0;i<startDow;i++) {
    const d = new Date(year, month, -startDow+i+1)
    days.push({ date:d.toISOString().split('T')[0], currentMonth:false })
  }
  for (let i=1;i<=lastDay.getDate();i++) {
    const d = new Date(year, month, i)
    days.push({ date:d.toISOString().split('T')[0], currentMonth:true })
  }
  // pad end to complete grid
  const remaining = 42-days.length
  for (let i=1;i<=remaining;i++) {
    const d = new Date(year, month+1, i)
    days.push({ date:d.toISOString().split('T')[0], currentMonth:false })
  }
  return days
}

function getWeekDaysRange(startDate) {
  const d = new Date(startDate)
  const dow = d.getDay()===0?6:d.getDay()-1
  d.setDate(d.getDate()-dow)
  return Array.from({length:7},(_,i)=>{
    const dd = new Date(d); dd.setDate(d.getDate()+i)
    return dd.toISOString().split('T')[0]
  })
}

function empColor(index) {
  const colors = ['#2563eb','#059669','#dc2626','#d97706','#7c3aed','#0891b2','#be185d','#65a30d','#ea580c','#0284c7']
  return colors[index % colors.length]
}

// ── MAIN PAGE ─────────────────────────────────────────────────────────────────
function KalenderPage() {
  const { user } = useAuth()
  const [viewMode, setViewMode] = useState('maned') // 'dag'|'uke'|'maned'
  const [currentDate, setCurrentDate] = useState(new Date().toISOString().split('T')[0])
  const [events, setEvents] = useState([])
  const [employees, setEmployees] = useState([])
  const [projects, setProjects] = useState([])
  const [attendees, setAttendees] = useState([])
  const [sharing, setSharing] = useState([])
  const [loading, setLoading] = useState(true)
  const [showNew, setShowNew] = useState(null) // date string to pre-fill
  const [selectedEvent, setSelectedEvent] = useState(null)
  const [editEvent, setEditEvent] = useState(null)
  const [calView, setCalView] = useState('mine') // 'mine'|'bedrift'
  const [visibleEmployees, setVisibleEmployees] = useState([])
  const [showSharingModal, setShowSharingModal] = useState(false)

  const load = async () => {
    try {
      const [ev, emp, proj, att, sh] = await Promise.all([
        supabase.from('calendar_events').select('*').order('start_date').then(r=>r.data||[]),
        supabase.from('employees').select('id,first_name,last_name').eq('status','Aktiv').order('last_name').then(r=>r.data||[]),
        supabase.from('projects').select('id,name').order('name').then(r=>r.data||[]),
        supabase.from('calendar_attendees').select('*').then(r=>r.data||[]),
        supabase.from('calendar_sharing').select('*').then(r=>r.data||[])
      ])
      setEvents(ev); setEmployees(emp); setProjects(proj); setAttendees(att); setSharing(sh)
      if (visibleEmployees.length===0) setVisibleEmployees(emp.slice(0,5).map(e=>e.id))
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(()=>{ load() },[])

  const today = new Date().toISOString().split('T')[0]
  const curDate = new Date(currentDate)

  const navigate = (dir) => {
    const d = new Date(currentDate)
    if (viewMode==='dag') d.setDate(d.getDate()+dir)
    else if (viewMode==='uke') d.setDate(d.getDate()+dir*7)
    else d.setMonth(d.getMonth()+dir)
    setCurrentDate(d.toISOString().split('T')[0])
  }

  const getEventsForDate = (date, empId=null) => {
    let evs = events.filter(e=> {
      const start = e.start_date
      const end = e.end_date||e.start_date
      return date>=start && date<=end
    })
    if (empId) {
      evs = evs.filter(e=> e.created_by===empId ||
        attendees.some(a=>a.event_id===e.id && a.employee_id===empId))
    }
    return evs
  }

  const getHolidayForDate = (date) => ALL_HOLIDAYS.find(h=>h.date===date)
  const isWeekend = (date) => { const d=new Date(date+'T12:00:00'); return d.getDay()===0||d.getDay()===6 }
  const isToday = (date) => date===today

  const headerLabel = () => {
    if (viewMode==='dag') return new Date(currentDate+'T12:00:00').toLocaleDateString('nb-NO',{weekday:'long',day:'numeric',month:'long',year:'numeric'})
    if (viewMode==='uke') {
      const days = getWeekDaysRange(currentDate)
      const s = new Date(days[0]+'T12:00:00'); const e = new Date(days[6]+'T12:00:00')
      return `${s.toLocaleDateString('nb-NO',{day:'numeric',month:'short'})} – ${e.toLocaleDateString('nb-NO',{day:'numeric',month:'short',year:'numeric'})}`
    }
    return `${MONTH_NAMES_NO[curDate.getMonth()]} ${curDate.getFullYear()}`
  }

  if (loading) return <div style={{ display:'flex',alignItems:'center',justifyContent:'center',minHeight:'60vh',fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px',height:'36px',border:'3px solid #e2e8f0',borderTop:'3px solid #059669',borderRadius:'50%',margin:'0 auto 12px',animation:'spin 1s linear infinite' }}/><p style={{ color:'#94a3b8',fontSize:'14px' }}>Laster kalender...</p></div></div>

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', display:'flex', flexDirection:'column', height:'100vh' }}>
      {/* Header */}
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding:'16px 24px', flexShrink:0 }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', flexWrap:'wrap', gap:'12px', marginBottom:'14px' }}>
          <h1 style={{ fontSize:'22px', fontWeight:'bold', color:'#0f172a', margin:0 }}>📆 Kalender</h1>
          <div style={{ display:'flex', gap:'8px' }}>
            <button onClick={()=>setShowSharingModal(true)} style={{ padding:'8px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'13px', color:'#475569', fontWeight:'500' }}>👥 Del kalender</button>
            <button onClick={()=>setShowNew(today)} style={{ padding:'9px 18px', background:'#059669', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize:'14px', fontWeight:'700' }}>+ Ny hendelse</button>
          </div>
        </div>

        <div style={{ display:'flex', gap:'10px', alignItems:'center', flexWrap:'wrap' }}>
          {/* Cal view toggle */}
          <div style={{ display:'flex', border:'1px solid #e2e8f0', borderRadius:'10px', overflow:'hidden' }}>
            {[['mine','👤 Min'],['bedrift','🏢 Bedrift']].map(([v,l])=>(
              <button key={v} onClick={()=>setCalView(v)}
                style={{ padding:'7px 14px', border:'none', background:calView===v?'#059669':'white', color:calView===v?'white':'#64748b', fontWeight:calView===v?'700':'500', fontSize:'13px', cursor:'pointer', borderRight:'1px solid #e2e8f0' }}>{l}</button>
            ))}
          </div>

          {/* View mode */}
          <div style={{ display:'flex', border:'1px solid #e2e8f0', borderRadius:'10px', overflow:'hidden' }}>
            {[['dag','Dag'],['uke','Uke'],['maned','Måned']].map(([v,l])=>(
              <button key={v} onClick={()=>setViewMode(v)}
                style={{ padding:'7px 14px', border:'none', background:viewMode===v?'#0f172a':'white', color:viewMode===v?'white':'#64748b', fontWeight:viewMode===v?'700':'500', fontSize:'13px', cursor:'pointer', borderRight:'1px solid #e2e8f0' }}>{l}</button>
            ))}
          </div>

          {/* Nav */}
          <div style={{ display:'flex', alignItems:'center', gap:'8px', marginLeft:'auto' }}>
            <button onClick={()=>navigate(-1)} style={{ width:'32px',height:'32px',borderRadius:'50%',border:'1px solid #e2e8f0',background:'white',cursor:'pointer',fontSize:'16px',display:'flex',alignItems:'center',justifyContent:'center' }}>‹</button>
            <span style={{ fontWeight:'700', color:'#0f172a', fontSize:'14px', minWidth:'180px', textAlign:'center' }}>{headerLabel()}</span>
            <button onClick={()=>navigate(1)} style={{ width:'32px',height:'32px',borderRadius:'50%',border:'1px solid #e2e8f0',background:'white',cursor:'pointer',fontSize:'16px',display:'flex',alignItems:'center',justifyContent:'center' }}>›</button>
            <button onClick={()=>setCurrentDate(today)} style={{ padding:'6px 12px',border:'1px solid #e2e8f0',borderRadius:'8px',background:'white',cursor:'pointer',fontSize:'12px',color:'#64748b' }}>I dag</button>
          </div>
        </div>

        {/* Bedrift view – employee filter */}
        {calView==='bedrift' && (
          <div style={{ display:'flex', gap:'8px', flexWrap:'wrap', marginTop:'12px' }}>
            {employees.map((emp,i)=>{
              const isVisible = visibleEmployees.includes(emp.id)
              const col = empColor(i)
              return (
                <button key={emp.id} onClick={()=>setVisibleEmployees(v=>isVisible?v.filter(x=>x!==emp.id):[...v,emp.id])}
                  style={{ display:'flex', alignItems:'center', gap:'6px', padding:'5px 12px', borderRadius:'999px', border:`2px solid ${isVisible?col:'#e2e8f0'}`, background:isVisible?col+'18':'white', cursor:'pointer', fontSize:'12px', fontWeight:'600', color:isVisible?col:'#94a3b8' }}>
                  <div style={{ width:'8px',height:'8px',borderRadius:'50%',background:isVisible?col:'#e2e8f0',flexShrink:0 }}/>
                  {emp.first_name} {emp.last_name}
                </button>
              )
            })}
          </div>
        )}
      </div>

      {/* Calendar body */}
      <div style={{ flex:1, overflow:'auto', background:'#f8fafc' }}>
        {viewMode==='maned' && (
          <CalMonthView
            year={curDate.getFullYear()} month={curDate.getMonth()}
            events={events} attendees={attendees} projects={projects}
            employees={employees} calView={calView} visibleEmployees={visibleEmployees}
            getEventsForDate={getEventsForDate} getHolidayForDate={getHolidayForDate}
            isWeekend={isWeekend} isToday={isToday} today={today}
            onDayClick={(date)=>setShowNew(date)}
            onEventClick={(ev)=>setSelectedEvent(ev)}
            user={user}
          />
        )}
        {viewMode==='uke' && (
          <CalWeekView
            currentDate={currentDate}
            events={events} attendees={attendees} projects={projects}
            employees={employees} calView={calView} visibleEmployees={visibleEmployees}
            getEventsForDate={getEventsForDate} getHolidayForDate={getHolidayForDate}
            isWeekend={isWeekend} isToday={isToday}
            onDayClick={(date)=>setShowNew(date)}
            onEventClick={(ev)=>setSelectedEvent(ev)}
            user={user}
          />
        )}
        {viewMode==='dag' && (
          <CalDayView
            date={currentDate}
            events={getEventsForDate(currentDate)}
            projects={projects} employees={employees} attendees={attendees}
            getHolidayForDate={getHolidayForDate}
            onNewEvent={()=>setShowNew(currentDate)}
            onEventClick={(ev)=>setSelectedEvent(ev)}
          />
        )}
      </div>

      {showNew && <EventModal date={showNew} projects={projects} employees={employees} user={user} onClose={()=>setShowNew(null)} onSaved={()=>{setShowNew(null);load()}} />}
      {selectedEvent && <EventDetailModal event={selectedEvent} projects={projects} employees={employees} attendees={attendees.filter(a=>a.event_id===selectedEvent.id)} user={user} onClose={()=>setSelectedEvent(null)} onEdit={()=>{setEditEvent(selectedEvent);setSelectedEvent(null)}} onDeleted={()=>{setSelectedEvent(null);load()}} />}
      {editEvent && <EventModal initial={editEvent} projects={projects} employees={employees} user={user} onClose={()=>setEditEvent(null)} onSaved={()=>{setEditEvent(null);load()}} />}
      {showSharingModal && <SharingModal user={user} employees={employees} sharing={sharing} onClose={()=>setShowSharingModal(false)} onSaved={()=>{setShowSharingModal(false);load()}} />}
    </div>
  )
}

function EventChip({ event, projects, compact=false, onClick }) {
  const cfg = EVENT_TYPES[event.type]||EVENT_TYPES.other
  const proj = projects.find(p=>p.id===event.project_id)
  const col = event.color||cfg.color
  return (
    <div onClick={e=>{e.stopPropagation();onClick&&onClick(event)}}
      style={{ background:col, borderRadius:'5px', padding:compact?'1px 5px':'3px 7px', marginBottom:'2px', cursor:'pointer', overflow:'hidden', userSelect:'none' }}>
      <div style={{ fontSize:'11px', fontWeight:'700', color:'white', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
        {!compact&&<span style={{ marginRight:'3px' }}>{cfg.emoji}</span>}{event.title}
      </div>
      {!compact&&event.start_time&&<div style={{ fontSize:'10px',color:'rgba(255,255,255,0.85)' }}>{event.start_time.slice(0,5)}{event.end_time?`–${event.end_time.slice(0,5)}`:''}</div>}
    </div>
  )
}

// ── MONTH VIEW ────────────────────────────────────────────────────────────────
function CalMonthView({ year, month, events, attendees, projects, employees, calView, visibleEmployees, getEventsForDate, getHolidayForDate, isWeekend, isToday, today, onDayClick, onEventClick, user }) {
  const days = getMonthDays(year, month)

  return (
    <div style={{ padding:'16px 24px' }}>
      <div style={{ display:'grid', gridTemplateColumns:'repeat(7,1fr)', gap:'1px', background:'#e2e8f0', borderRadius:'14px', overflow:'hidden', border:'1px solid #e2e8f0' }}>
        {/* Day headers */}
        {DAY_SHORT_NO.map(d=>(
          <div key={d} style={{ background:'#f8fafc', padding:'10px', textAlign:'center', fontSize:'12px', fontWeight:'700', color:'#64748b', textTransform:'uppercase' }}>{d}</div>
        ))}
        {/* Day cells */}
        {days.map(({date,currentMonth})=>{
          const holiday = getHolidayForDate(date)
          const weekend = isWeekend(date)
          const today_ = isToday(date)
          const dayEvs = calView==='bedrift'
            ? events.filter(e=>{
                const start=e.start_date; const end=e.end_date||e.start_date
                if (!(date>=start&&date<=end)) return false
                if (e.visibility==='public') return true
                return visibleEmployees.some(empId=>
                  e.created_by===empId || attendees.some(a=>a.event_id===e.id)
                )
              })
            : getEventsForDate(date)
          const maxShow = 3

          return (
            <div key={date} onClick={()=>currentMonth&&onDayClick(date)}
              style={{ background:!currentMonth?'#fafafa':holiday?'#fef9ec':weekend?'#fafafe':'white', minHeight:'100px', padding:'6px', cursor:currentMonth?'pointer':'default', position:'relative' }}
              onMouseEnter={e=>{if(currentMonth)e.currentTarget.style.background=today_?'#ecfdf5':'#f8fafc'}}
              onMouseLeave={e=>{e.currentTarget.style.background=!currentMonth?'#fafafa':holiday?'#fef9ec':weekend?'#fafafe':'white'}}>
              {/* Date number */}
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'4px' }}>
                <span style={{ width:'24px',height:'24px',borderRadius:'50%',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'13px',fontWeight:today_?'800':'500',background:today_?'#059669':'transparent',color:today_?'white':!currentMonth?'#cbd5e1':weekend?'#94a3b8':'#0f172a' }}>
                  {new Date(date+'T12:00:00').getDate()}
                </span>
                {holiday&&<span style={{ fontSize:'9px',color:'#d97706',fontWeight:'700',textAlign:'right',maxWidth:'60px',lineHeight:1.2 }}>{holiday.title}</span>}
              </div>
              {/* Events */}
              {dayEvs.slice(0,maxShow).map(ev=>(
                <EventChip key={ev.id} event={ev} projects={projects} compact={false} onClick={onEventClick} />
              ))}
              {dayEvs.length>maxShow&&<div style={{ fontSize:'10px',color:'#94a3b8',fontWeight:'600' }}>+{dayEvs.length-maxShow} til</div>}
            </div>
          )
        })}
      </div>
    </div>
  )
}

// ── WEEK VIEW ─────────────────────────────────────────────────────────────────
function CalWeekView({ currentDate, events, attendees, projects, employees, calView, visibleEmployees, getEventsForDate, getHolidayForDate, isWeekend, isToday, onDayClick, onEventClick, user }) {
  const days = getWeekDaysRange(currentDate)

  if (calView==='bedrift') {
    // Bedrift view: rows=employees, cols=days
    const visEmp = employees.filter(e=>visibleEmployees.includes(e.id))
    return (
      <div style={{ padding:'0 24px 24px' }}>
        <div style={{ overflowX:'auto', flex:fullscreen?1:'initial', overflow:fullscreen?'auto':'initial' }}>
          <table style={{ width:'100%', borderCollapse:'collapse', background:'white', borderRadius:'14px', overflow:'hidden', boxShadow:'0 1px 4px rgba(0,0,0,0.06)' }}>
            <thead>
              <tr>
                <th style={{ padding:'10px 16px', textAlign:'left', fontSize:'12px', fontWeight:'700', color:'#64748b', background:'#f8fafc', width:'150px', borderBottom:'1px solid #f1f5f9' }}>Ansatt</th>
                {days.map((date,i)=>{
                  const holiday=getHolidayForDate(date); const weekend=isWeekend(date); const tod=isToday(date)
                  const d=new Date(date+'T12:00:00')
                  return (
                    <th key={date} style={{ padding:'8px 6px', textAlign:'center', background:tod?'#f0fdf4':weekend?'#fafafa':'#f8fafc', borderBottom:`2px solid ${tod?'#059669':'#f1f5f9'}`, minWidth:'120px' }}>
                      <div style={{ fontSize:'11px',fontWeight:'600',color:tod?'#059669':'#94a3b8',textTransform:'uppercase' }}>{DAY_SHORT_NO[i]}</div>
                      <div style={{ fontSize:'14px',fontWeight:tod?'800':'600',color:tod?'#059669':'#0f172a' }}>{d.getDate()}</div>
                      {holiday&&<div style={{ fontSize:'9px',color:'#d97706',fontWeight:'600' }}>{holiday.title}</div>}
                    </th>
                  )
                })}
              </tr>
            </thead>
            <tbody>
              {visEmp.map((emp,ei)=>(
                <tr key={emp.id}>
                  <td style={{ padding:'8px 16px', borderBottom:'1px solid #f8fafc', borderRight:'1px solid #f1f5f9' }}>
                    <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
                      <div style={{ width:'30px',height:'30px',borderRadius:'50%',background:empColor(ei)+'20',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'11px',fontWeight:'800',color:empColor(ei),flexShrink:0 }}>{emp.first_name?.[0]}{emp.last_name?.[0]}</div>
                      <div style={{ fontSize:'12px',fontWeight:'600',color:'#0f172a',lineHeight:1.2 }}>{emp.first_name}<br/>{emp.last_name}</div>
                    </div>
                  </td>
                  {days.map((date,di)=>{
                    const dayEvs = events.filter(e=>{
                      const start=e.start_date; const end=e.end_date||e.start_date
                      if (!(date>=start&&date<=end)) return false
                      return e.created_by===emp.id || attendees.some(a=>a.event_id===e.id&&a.employee_id===emp.id)
                    })
                    const weekend=isWeekend(date); const tod=isToday(date)
                    return (
                      <td key={date} style={{ padding:'4px 6px', verticalAlign:'top', background:tod?'#f9fffe':weekend?'#fafafa':'white', borderBottom:'1px solid #f8fafc', borderRight:'1px solid #f8fafc', minHeight:'60px', cursor:'pointer' }}
                        onClick={()=>onDayClick(date)}>
                        {dayEvs.map(ev=><EventChip key={ev.id} event={ev} projects={projects} compact={false} onClick={onEventClick} />)}
                        {dayEvs.length===0&&!weekend&&<div style={{ height:'40px',display:'flex',alignItems:'center',justifyContent:'center',opacity:0.1 }}><span style={{ fontSize:'18px',color:'#059669' }}>+</span></div>}
                      </td>
                    )
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    )
  }

  // Personal week view
  return (
    <div style={{ padding:'0 24px 24px' }}>
      <div style={{ display:'grid', gridTemplateColumns:'repeat(7,1fr)', gap:'8px' }}>
        {days.map((date,i)=>{
          const dayEvs = getEventsForDate(date)
          const holiday=getHolidayForDate(date); const weekend=isWeekend(date); const tod=isToday(date)
          const d=new Date(date+'T12:00:00')
          return (
            <div key={date} style={{ background:'white', borderRadius:'12px', border:`2px solid ${tod?'#059669':weekend?'#f1f5f9':'#f1f5f9'}`, overflow:'hidden', minHeight:'200px' }}>
              <div onClick={()=>onDayClick(date)} style={{ padding:'10px 12px', background:tod?'#f0fdf4':weekend?'#fafafa':'#f8fafc', cursor:'pointer', borderBottom:'1px solid #f1f5f9' }}>
                <div style={{ fontSize:'11px',fontWeight:'700',color:tod?'#059669':'#94a3b8',textTransform:'uppercase' }}>{DAY_NAMES_NO[i]}</div>
                <div style={{ fontSize:'20px',fontWeight:'800',color:tod?'#059669':weekend?'#cbd5e1':'#0f172a' }}>{d.getDate()}</div>
                {holiday&&<div style={{ fontSize:'10px',color:'#d97706',fontWeight:'600' }}>{holiday.title}</div>}
              </div>
              <div style={{ padding:'6px' }}>
                {dayEvs.map(ev=><EventChip key={ev.id} event={ev} projects={projects} onClick={onEventClick} />)}
              </div>
            </div>
          )
        })}
      </div>
    </div>
  )
}

// ── DAY VIEW ──────────────────────────────────────────────────────────────────
function CalDayView({ date, events, projects, employees, attendees, getHolidayForDate, onNewEvent, onEventClick }) {
  const holiday=getHolidayForDate(date)
  const hours = Array.from({length:24},(_,i)=>i)
  const getEventsForHour = (h) => events.filter(e=>{ if(!e.start_time) return false; const eh=parseInt(e.start_time.split(':')[0]); return eh===h })
  const allDayEvs = events.filter(e=>e.all_day||!e.start_time)

  return (
    <div style={{ padding:'16px 24px', display:'flex', flexDirection:'column', gap:'12px' }}>
      {holiday&&<div style={{ background:'#fffbeb',borderRadius:'10px',padding:'10px 14px',border:'1px solid #fde68a',fontSize:'13px',color:'#92400e',fontWeight:'600' }}>🗓️ {holiday.title}</div>}
      {allDayEvs.length>0&&(
        <div style={{ background:'white',borderRadius:'12px',border:'1px solid #f1f5f9',padding:'12px 16px' }}>
          <div style={{ fontSize:'12px',fontWeight:'700',color:'#64748b',marginBottom:'8px',textTransform:'uppercase' }}>Heldagshendelser</div>
          {allDayEvs.map(ev=><EventChip key={ev.id} event={ev} projects={projects} onClick={onEventClick} />)}
        </div>
      )}
      <div style={{ background:'white',borderRadius:'14px',border:'1px solid #f1f5f9',overflow:'hidden' }}>
        {hours.filter(h=>h>=6&&h<=22).map(h=>{
          const hEvs = getEventsForHour(h)
          return (
            <div key={h} onClick={()=>hEvs.length===0&&onNewEvent()} style={{ display:'flex',minHeight:'56px',borderBottom:'1px solid #f8fafc',cursor:'pointer' }}
              onMouseEnter={e=>{if(!hEvs.length)e.currentTarget.style.background='#f8fafc'}} onMouseLeave={e=>{e.currentTarget.style.background='white'}}>
              <div style={{ width:'60px',flexShrink:0,padding:'8px 12px',fontSize:'12px',fontWeight:'600',color:'#94a3b8',borderRight:'1px solid #f1f5f9',textAlign:'right' }}>
                {String(h).padStart(2,'0')}:00
              </div>
              <div style={{ flex:1,padding:'4px 8px' }}>
                {hEvs.map(ev=><EventChip key={ev.id} event={ev} projects={projects} onClick={onEventClick} />)}
              </div>
            </div>
          )
        })}
      </div>
    </div>
  )
}

// ── EVENT MODAL ───────────────────────────────────────────────────────────────
function EventModal({ date, initial, projects, employees, user, onClose, onSaved }) {
  const isEdit = !!initial
  const [form, setForm] = useState({
    title: initial?.title||'',
    type: initial?.type||'meeting',
    start_date: initial?.start_date||date||new Date().toISOString().split('T')[0],
    end_date: initial?.end_date||'',
    start_time: initial?.start_time||'',
    end_time: initial?.end_time||'',
    all_day: initial?.all_day||false,
    location: initial?.location||'',
    description: initial?.description||'',
    project_id: initial?.project_id||'',
    color: initial?.color||'',
    visibility: initial?.visibility||'private',
  })
  const [selectedAttendees, setSelectedAttendees] = useState([])
  const [saving, setSaving] = useState(false)
  const set = (k,v) => setForm(f=>({...f,[k]:v}))

  const handleSave = async () => {
    if (!form.title.trim()) return alert('Tittel er påkrevd')
    setSaving(true)
    try {
      const payload = { ...form, project_id:form.project_id||null, end_date:form.end_date||form.start_date, updated_at:new Date().toISOString() }
      let evId = initial?.id
      if (isEdit) {
        const {error}=await supabase.from('calendar_events').update(payload).eq('id',initial.id)
        if (error) throw error
        await supabase.from('calendar_attendees').delete().eq('event_id',initial.id)
      } else {
        const {data,error}=await supabase.from('calendar_events').insert({...payload,created_by:user?.id}).select().single()
        if (error) throw error
        evId = data.id
      }
      if (selectedAttendees.length>0) {
        await supabase.from('calendar_attendees').insert(selectedAttendees.map(empId=>({ event_id:evId, employee_id:empId, status:'invited' })))
      }
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  const lbl = t => <label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'6px' }}>{t}</label>

  return (
    <div style={{ position:'fixed',inset:0,zIndex:100,display:'flex',alignItems:'center',justifyContent:'center',padding:'16px' }}>
      <div style={{ position:'absolute',inset:0,background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative',background:'white',borderRadius:'20px',width:'100%',maxWidth:'580px',maxHeight:'92vh',display:'flex',flexDirection:'column',boxShadow:'0 20px 60px rgba(0,0,0,0.2)',fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding:'18px 24px',borderBottom:'1px solid #f1f5f9',display:'flex',justifyContent:'space-between',alignItems:'center',flexShrink:0 }}>
          <h2 style={{ margin:0,fontSize:'18px',fontWeight:'700',color:'#0f172a' }}>{isEdit?'Rediger':'Ny'} hendelse</h2>
          <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
            <button type="button" onClick={onClose} style={{ padding:'8px 16px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleSave} disabled={saving} style={{ padding:'8px 20px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize:'14px', fontWeight:'700' }}>{saving?'Lagrer...':isEdit?'Lagre':'Opprett hendelse'}</button>
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8', marginLeft:'4px' }}>×</button>
          </div>
        </div>
        <div style={{ overflowY:'auto',flex:1,padding:'20px 24px',display:'flex',flexDirection:'column',gap:'14px' }}>

          {/* Type selector */}
          <div>
            {lbl('Type hendelse')}
            <div style={{ display:'flex',gap:'6px',flexWrap:'wrap' }}>
              {Object.entries(EVENT_TYPES).map(([k,cfg])=>(
                <button key={k} type="button" onClick={()=>{ set('type',k); set('color',cfg.color) }}
                  style={{ padding:'6px 12px',borderRadius:'8px',border:`2px solid ${form.type===k?cfg.color:'#e2e8f0'}`,background:form.type===k?cfg.bg:'white',color:form.type===k?cfg.color:'#64748b',fontWeight:form.type===k?'700':'500',fontSize:'12px',cursor:'pointer' }}>
                  {cfg.emoji} {cfg.label}
                </button>
              ))}
            </div>
          </div>

          <div>{lbl('Tittel *')}<input value={form.title} onChange={e=>set('title',e.target.value)} placeholder="Beskriv hendelsen" style={cInp} /></div>

          <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:'12px' }}>
            <div>{lbl('Fra dato')}<input type="date" value={form.start_date} onChange={e=>set('start_date',e.target.value)} style={cInp} /></div>
            <div>{lbl('Til dato (valgfritt)')}<input type="date" value={form.end_date} onChange={e=>set('end_date',e.target.value)} style={cInp} /></div>
          </div>

          <div>
            <label style={{ display:'flex',alignItems:'center',gap:'8px',cursor:'pointer',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'8px' }}>
              <input type="checkbox" checked={form.all_day} onChange={e=>set('all_day',e.target.checked)} style={{ width:'16px',height:'16px',accentColor:'#059669' }} />
              Heldagshendelse
            </label>
            {!form.all_day&&(
              <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:'12px' }}>
                <div>{lbl('Fra kl.')}<input type="time" value={form.start_time} onChange={e=>set('start_time',e.target.value)} style={cInp} /></div>
                <div>{lbl('Til kl.')}<input type="time" value={form.end_time} onChange={e=>set('end_time',e.target.value)} style={cInp} /></div>
              </div>
            )}
          </div>

          <div>{lbl('Sted / Lokasjon')}<input value={form.location} onChange={e=>set('location',e.target.value)} placeholder="F.eks. Møterom A, Byggeplass..." style={cInp} /></div>
          <div>{lbl('Knytt til prosjekt')}<select value={form.project_id} onChange={e=>set('project_id',e.target.value)} style={cInp}><option value="">Ingen</option>{projectOptions(projects).map(p => <option key={p.id} value={p.id}>{'  '.repeat(p._depth)}{p._depth > 0 ? '└ ' : ''}{p.name}{p.project_number ? ` (${p.project_number})` : ''}</option>)}</select></div>
          <div>{lbl('Beskrivelse')}<textarea value={form.description} onChange={e=>set('description',e.target.value)} rows={3} style={{ ...cInp,resize:'none' }} placeholder="Valgfri beskrivelse..." /></div>

          {/* Visibility */}
          <div>
            {lbl('Synlighet')}
            <div style={{ display:'flex',gap:'8px' }}>
              {[['private','🔒 Privat'],['shared','👥 Delt med valgte'],['public','🏢 Alle ansatte']].map(([v,l])=>(
                <button key={v} type="button" onClick={()=>set('visibility',v)}
                  style={{ flex:1,padding:'8px',borderRadius:'8px',border:`2px solid ${form.visibility===v?'#059669':'#e2e8f0'}`,background:form.visibility===v?'#f0fdf4':'white',color:form.visibility===v?'#059669':'#64748b',fontWeight:form.visibility===v?'700':'500',fontSize:'12px',cursor:'pointer' }}>{l}</button>
              ))}
            </div>
          </div>

          {/* Attendees */}
          {(form.visibility==='shared'||form.visibility==='public') && (
            <div>
              {lbl('Inviter ansatte')}
              <div style={{ display:'flex',flexWrap:'wrap',gap:'6px' }}>
                {employees.map((emp,i)=>{
                  const isSelected = selectedAttendees.includes(emp.id)
                  return (
                    <button key={emp.id} type="button" onClick={()=>setSelectedAttendees(s=>isSelected?s.filter(x=>x!==emp.id):[...s,emp.id])}
                      style={{ padding:'5px 12px',borderRadius:'999px',border:`2px solid ${isSelected?empColor(i):'#e2e8f0'}`,background:isSelected?empColor(i)+'18':'white',color:isSelected?empColor(i):'#64748b',fontWeight:isSelected?'700':'500',fontSize:'12px',cursor:'pointer' }}>
                      {emp.first_name} {emp.last_name}
                    </button>
                  )
                })}
              </div>
            </div>
          )}
        </div>

      </div>
    </div>
  )
}

// ── EVENT DETAIL MODAL ────────────────────────────────────────────────────────
function EventDetailModal({ event, projects, employees, attendees, user, onClose, onEdit, onDeleted }) {
  const confirm = useConfirm()
  const cfg = EVENT_TYPES[event.type]||EVENT_TYPES.other
  const proj = projects.find(p=>p.id===event.project_id)
  const col = event.color||cfg.color

  const handleDelete = async () => {
    if (!(await confirm({ message: 'Slett denne hendelsen?', subMessage: 'Kalenderhendelsen slettes permanent.', danger: true }))) return
    await supabase.from('calendar_events').delete().eq('id',event.id)
    onDeleted()
  }

  return (
    <div style={{ position:'fixed',inset:0,zIndex:100,display:'flex',alignItems:'center',justifyContent:'center',padding:'16px' }}>
      <div style={{ position:'absolute',inset:0,background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative',background:'white',borderRadius:'20px',width:'100%',maxWidth:'460px',boxShadow:'0 20px 60px rgba(0,0,0,0.2)',fontFamily:'system-ui,sans-serif',overflow:'hidden' }}>
        <div style={{ background:col,padding:'20px 24px' }}>
          <div style={{ display:'flex',justifyContent:'space-between',alignItems:'flex-start' }}>
            <div>
              <div style={{ fontSize:'12px',fontWeight:'700',color:'rgba(255,255,255,0.8)',marginBottom:'4px' }}>{cfg.emoji} {cfg.label}</div>
              <h2 style={{ margin:0,fontSize:'20px',fontWeight:'800',color:'white' }}>{event.title}</h2>
            </div>
            <button onClick={onClose} style={{ background:'rgba(255,255,255,0.2)',border:'none',borderRadius:'50%',width:'32px',height:'32px',cursor:'pointer',color:'white',fontSize:'18px',display:'flex',alignItems:'center',justifyContent:'center' }}>×</button>
          </div>
        </div>
        <div style={{ padding:'20px 24px',display:'flex',flexDirection:'column',gap:'12px' }}>
          <div style={{ display:'grid',gridTemplateColumns:'auto 1fr',gap:'8px 14px',alignItems:'center' }}>
            <span style={{ fontSize:'16px' }}>📅</span>
            <span style={{ fontSize:'14px',color:'#0f172a',fontWeight:'500' }}>
              {event.start_date}{event.end_date&&event.end_date!==event.start_date?` – ${event.end_date}`:''}
              {event.start_time&&<span style={{ color:'#64748b' }}> · {event.start_time.slice(0,5)}{event.end_time?`–${event.end_time.slice(0,5)}`:''}</span>}
            </span>
            {event.location&&<><span style={{ fontSize:'16px' }}>📍</span><span style={{ fontSize:'14px',color:'#0f172a' }}>{event.location}</span></>}
            {proj&&<><span style={{ fontSize:'16px' }}>🏗️</span><span style={{ fontSize:'14px',color:'#2563eb',fontWeight:'500' }}>{proj.name}</span></>}
            {event.visibility&&<><span style={{ fontSize:'16px' }}>{event.visibility==='private'?'🔒':event.visibility==='shared'?'👥':'🏢'}</span><span style={{ fontSize:'13px',color:'#64748b' }}>{event.visibility==='private'?'Privat':event.visibility==='shared'?'Delt':'Alle ansatte'}</span></>}
          </div>
          {event.description&&<p style={{ margin:0,fontSize:'14px',color:'#475569',lineHeight:1.6,background:'#f8fafc',borderRadius:'10px',padding:'10px 14px' }}>{event.description}</p>}
          {attendees.length>0&&(
            <div>
              <div style={{ fontSize:'12px',fontWeight:'700',color:'#64748b',textTransform:'uppercase',marginBottom:'6px' }}>Inviterte</div>
              <div style={{ display:'flex',flexWrap:'wrap',gap:'6px' }}>
                {attendees.map(a=>{
                  const emp=employees.find(e=>e.id===a.employee_id)
                  if (!emp) return null
                  return <span key={a.id} style={{ background:'#f0fdf4',color:'#16a34a',border:'1px solid #bbf7d0',borderRadius:'999px',padding:'3px 10px',fontSize:'12px',fontWeight:'600' }}>{emp.first_name} {emp.last_name}</span>
                })}
              </div>
            </div>
          )}
          <div style={{ display:'flex',gap:'8px',borderTop:'1px solid #f1f5f9',paddingTop:'12px' }}>
            <button onClick={handleDelete} style={{ padding:'9px 14px',border:'1px solid #fecaca',borderRadius:'10px',background:'white',cursor:'pointer',color:'#dc2626',fontSize:'13px',fontWeight:'600' }}>🗑️ Slett</button>
            <button onClick={onClose} style={{ flex:1,padding:'9px',border:'1px solid #e2e8f0',borderRadius:'10px',background:'white',cursor:'pointer',fontSize:'13px',fontWeight:'600',color:'#374151' }}>Lukk</button>
            <button onClick={onEdit} style={{ flex:1,padding:'9px',background:'#059669',color:'white',border:'none',borderRadius:'10px',cursor:'pointer',fontSize:'13px',fontWeight:'700' }}>✏️ Rediger</button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ── SHARING MODAL ─────────────────────────────────────────────────────────────
function SharingModal({ user, employees, sharing, onClose, onSaved }) {
  const [selected, setSelected] = useState(sharing.filter(s=>s.owner_id===user?.id).map(s=>s.shared_with_id))
  const [saving, setSaving] = useState(false)

  const handleSave = async () => {
    setSaving(true)
    try {
      // Remove all existing shares by this user
      await supabase.from('calendar_sharing').delete().eq('owner_id',user?.id)
      // Insert new
      if (selected.length>0) {
        await supabase.from('calendar_sharing').insert(selected.map(id=>({ owner_id:user?.id, shared_with_id:id })))
      }
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  const sharedWithMe = sharing.filter(s=>s.shared_with_id===user?.id).map(s=>{
    return employees.find(e=>e.id===s.owner_id)
  }).filter(Boolean)

  return (
    <div style={{ position:'fixed',inset:0,zIndex:100,display:'flex',alignItems:'center',justifyContent:'center',padding:'16px' }}>
      <div style={{ position:'absolute',inset:0,background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative',background:'white',borderRadius:'20px',width:'100%',maxWidth:'460px',boxShadow:'0 20px 60px rgba(0,0,0,0.2)',fontFamily:'system-ui,sans-serif',overflow:'hidden' }}>
        <div style={{ padding:'20px 24px',borderBottom:'1px solid #f1f5f9',display:'flex',justifyContent:'space-between',alignItems:'center' }}>
          <h2 style={{ margin:0,fontSize:'18px',fontWeight:'700',color:'#0f172a' }}>👥 Del din kalender</h2>
          <button onClick={onClose} style={{ background:'none',border:'none',fontSize:'22px',cursor:'pointer',color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding:'20px 24px',display:'flex',flexDirection:'column',gap:'16px' }}>
          <div>
            <div style={{ fontSize:'13px',fontWeight:'700',color:'#0f172a',marginBottom:'10px' }}>Del din kalender med:</div>
            <div style={{ display:'flex',flexDirection:'column',gap:'8px' }}>
              {employees.map((emp,i)=>{
                const isSelected=selected.includes(emp.id)
                return (
                  <div key={emp.id} onClick={()=>setSelected(s=>isSelected?s.filter(x=>x!==emp.id):[...s,emp.id])}
                    style={{ display:'flex',alignItems:'center',gap:'12px',padding:'10px 14px',borderRadius:'12px',border:`2px solid ${isSelected?empColor(i):'#e2e8f0'}`,background:isSelected?empColor(i)+'10':'white',cursor:'pointer' }}>
                    <div style={{ width:'36px',height:'36px',borderRadius:'50%',background:empColor(i)+'20',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'13px',fontWeight:'800',color:empColor(i),flexShrink:0 }}>{emp.first_name?.[0]}{emp.last_name?.[0]}</div>
                    <span style={{ flex:1,fontSize:'14px',fontWeight:'600',color:'#0f172a' }}>{emp.first_name} {emp.last_name}</span>
                    {isSelected&&<span style={{ fontSize:'18px',color:empColor(i) }}>✓</span>}
                  </div>
                )
              })}
            </div>
          </div>

          {sharedWithMe.length>0&&(
            <div style={{ background:'#f0fdf4',borderRadius:'12px',padding:'14px',border:'1px solid #bbf7d0' }}>
              <div style={{ fontSize:'12px',fontWeight:'700',color:'#16a34a',marginBottom:'8px' }}>Disse har delt sin kalender med deg:</div>
              <div style={{ display:'flex',flexWrap:'wrap',gap:'6px' }}>
                {sharedWithMe.map(emp=>(
                  <span key={emp.id} style={{ background:'white',border:'1px solid #bbf7d0',borderRadius:'999px',padding:'3px 10px',fontSize:'12px',fontWeight:'600',color:'#16a34a' }}>{emp.first_name} {emp.last_name}</span>
                ))}
              </div>
            </div>
          )}

          <div style={{ display:'flex',justifyContent:'flex-end',gap:'12px',borderTop:'1px solid #f1f5f9',paddingTop:'14px' }}>
            <button onClick={onClose} style={{ padding:'10px 20px',border:'1px solid #e2e8f0',borderRadius:'10px',background:'white',cursor:'pointer',fontSize:'14px',fontWeight:'600',color:'#374151' }}>Avbryt</button>
            <button onClick={handleSave} disabled={saving} style={{ padding:'10px 24px',background:saving?'#6ee7b7':'#059669',color:'white',border:'none',borderRadius:'10px',cursor:saving?'not-allowed':'pointer',fontSize:'14px',fontWeight:'700' }}>
              {saving?'Lagrer...':'Lagre delingsinnstillinger'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ─── END KALENDER MODULE ──────────────────────────────────────────────────────


// ─── INTERN CHAT MODULE ───────────────────────────────────────────────────────

const CHAT_COLORS = ['#2563eb','#059669','#dc2626','#d97706','#7c3aed','#0891b2','#be185d','#65a30d']
function chatColor(str) { let h=0; for(let c of (str||'')) h=c.charCodeAt(0)+((h<<5)-h); return CHAT_COLORS[Math.abs(h)%CHAT_COLORS.length] }

function ChatAvatar({ name, size=32 }) {
  const initials=(name||'?').split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase()
  const bg=chatColor(name)
  return <div style={{ width:size,height:size,borderRadius:'50%',background:bg,display:'flex',alignItems:'center',justifyContent:'center',fontSize:size*0.36,fontWeight:'800',color:'white',flexShrink:0 }}>{initials}</div>
}

function fmtChatTime(ts) {
  const d=new Date(ts), now=new Date()
  const diffDays=Math.floor((now-d)/(1000*60*60*24))
  if (diffDays===0) return d.toLocaleTimeString('nb-NO',{hour:'2-digit',minute:'2-digit'})
  if (diffDays===1) return 'I går'
  if (diffDays<7) return d.toLocaleDateString('nb-NO',{weekday:'short'})
  return d.toLocaleDateString('nb-NO',{day:'numeric',month:'short'})
}

function InterChatPage() {
  const { user } = useAuth()
  const [channels, setChannels] = useState([])
  const [employees, setEmployees] = useState([])
  const [projects, setProjects] = useState([])
  const [members, setMembers] = useState([])
  const [selectedChannel, setSelectedChannel] = useState(null)
  const [loading, setLoading] = useState(true)
  const [showNewChannel, setShowNewChannel] = useState(false)
  const [search, setSearch] = useState('')
  const [expandedProjects, setExpandedProjects] = useState({})

  const load = async () => {
    try {
      const [ch, emp, proj, mem] = await Promise.all([
        supabase.from('chat_channels').select('*, chat_messages(id,content,created_at,sender_id)').order('updated_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('employees').select('id,first_name,last_name').eq('status','Aktiv').order('first_name').then(r=>r.data||[]),
        supabase.from('projects').select('id,name').order('name').then(r=>r.data||[]),
        supabase.from('chat_members').select('*').then(r=>r.data||[])
      ])
      setChannels(ch); setEmployees(emp); setProjects(proj); setMembers(mem)
      // Auto-expand all projects
      const expanded = {}
      proj.forEach(p=>{ expanded[p.id]=true })
      expanded['general']=true
      setExpandedProjects(expanded)
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }

  useEffect(()=>{ load() },[])

  useEffect(()=>{
    const sub = supabase.channel('chat-global-v2')
      .on('postgres_changes',{event:'*',schema:'public',table:'chat_messages'},()=>load())
      .subscribe()
    return ()=>supabase.removeChannel(sub)
  },[])

  const getLastMsg = (ch) => {
    const msgs=(ch.chat_messages||[]).sort((a,b)=>new Date(b.created_at)-new Date(a.created_at))
    return msgs[0]
  }

  const getMemberCount = (chId) => members.filter(m=>m.channel_id===chId).length

  // Group channels: project channels under their project, others under "Generelt"
  const projectChannels = {} // projectId -> channels[]
  const generalChannels = []
  const directChannels = []

  channels.filter(ch=>
    ch.name?.toLowerCase().includes(search.toLowerCase()) ||
    !search
  ).forEach(ch=>{
    if (ch.type==='direct') { directChannels.push(ch); return }
    if (ch.project_id) {
      if (!projectChannels[ch.project_id]) projectChannels[ch.project_id]=[]
      projectChannels[ch.project_id].push(ch)
    } else {
      generalChannels.push(ch)
    }
  })

  const toggleProject = (id) => setExpandedProjects(v=>({...v,[id]:!v[id]}))

  const ChannelItem = ({ ch }) => {
    const isSelected = selectedChannel?.id===ch.id
    const lastMsg = getLastMsg(ch)
    const memberCount = getMemberCount(ch.id)
    return (
      <div onClick={()=>setSelectedChannel(ch)}
        style={{ display:'flex',alignItems:'center',gap:'10px',padding:'8px 12px',borderRadius:'10px',cursor:'pointer',background:isSelected?'#f0fdf4':'transparent',border:isSelected?'1px solid #bbf7d0':'1px solid transparent',marginBottom:'2px',transition:'all 0.1s' }}
        onMouseEnter={e=>{if(!isSelected){e.currentTarget.style.background='#f8fafc';e.currentTarget.style.borderColor='#f1f5f9'}}}
        onMouseLeave={e=>{if(!isSelected){e.currentTarget.style.background='transparent';e.currentTarget.style.borderColor='transparent'}}}>
        <div style={{ width:'36px',height:'36px',borderRadius:'10px',background:isSelected?'#dcfce7':chatColor(ch.name)+'18',border:`1px solid ${isSelected?'#bbf7d0':chatColor(ch.name)+'30'}`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:'15px',flexShrink:0 }}>
          {ch.type==='direct'?'👤':'#'}
        </div>
        <div style={{ flex:1,minWidth:0 }}>
          <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center' }}>
            <span style={{ fontWeight:isSelected?'700':'600',fontSize:'13px',color:isSelected?'#059669':'#0f172a',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{ch.name}</span>
            {lastMsg&&<span style={{ fontSize:'10px',color:'#94a3b8',flexShrink:0 }}>{fmtChatTime(lastMsg.created_at)}</span>}
          </div>
          <div style={{ fontSize:'11px',color:'#94a3b8',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap',marginTop:'1px' }}>
            {lastMsg ? (lastMsg.content||'📎 Fil') : `${memberCount} medlemmer`}
          </div>
        </div>
      </div>
    )
  }

  const ProjectSection = ({ projectId, label, chs }) => {
    const isOpen = expandedProjects[projectId]!==false
    return (
      <div style={{ marginBottom:'8px' }}>
        <div onClick={()=>toggleProject(projectId)}
          style={{ display:'flex',alignItems:'center',gap:'8px',padding:'6px 8px',cursor:'pointer',borderRadius:'8px',marginBottom:'4px' }}
          onMouseEnter={e=>e.currentTarget.style.background='#f8fafc'} onMouseLeave={e=>e.currentTarget.style.background='transparent'}>
          <span style={{ fontSize:'12px',color:'#94a3b8',fontWeight:'700',transition:'transform 0.2s',display:'inline-block',transform:isOpen?'rotate(90deg)':'none' }}>›</span>
          <span style={{ fontSize:'11px',fontWeight:'700',color:'#64748b',textTransform:'uppercase',letterSpacing:'0.05em',flex:1 }}>
            {projectId!=='general'&&projectId!=='direct'?'🏗️ ':''}{label}
          </span>
          <span style={{ fontSize:'10px',color:'#cbd5e1',fontWeight:'600' }}>{chs.length}</span>
        </div>
        {isOpen&&(
          <div style={{ paddingLeft:'8px' }}>
            {chs.map(ch=><ChannelItem key={ch.id} ch={ch} />)}
            {projectId!=='direct'&&(
              <button onClick={()=>setShowNewChannel(projectId)}
                style={{ display:'flex',alignItems:'center',gap:'6px',padding:'6px 12px',border:'none',background:'transparent',cursor:'pointer',fontSize:'12px',color:'#94a3b8',width:'100%',borderRadius:'8px',textAlign:'left' }}
                onMouseEnter={e=>e.currentTarget.style.color='#059669'} onMouseLeave={e=>e.currentTarget.style.color='#94a3b8'}>
                <span style={{ fontSize:'14px' }}>+</span> Legg til kanal
              </button>
            )}
          </div>
        )}
      </div>
    )
  }

  if (loading) return <div style={{ display:'flex',alignItems:'center',justifyContent:'center',minHeight:'60vh',fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px',height:'36px',border:'3px solid #e2e8f0',borderTop:'3px solid #059669',borderRadius:'50%',margin:'0 auto 12px',animation:'spin 1s linear infinite' }}/><p style={{ color:'#94a3b8',fontSize:'14px' }}>Laster Intern Chat...</p></div></div>

  return (
    <div style={{ display:'flex',height:'calc(100vh - 64px)',fontFamily:'system-ui,sans-serif',overflow:'hidden',background:'#f8fafc' }}>
      {/* LEFT SIDEBAR */}
      <div style={{ width:'280px',flexShrink:0,background:'white',borderRight:'1px solid #f1f5f9',display:'flex',flexDirection:'column',height:'100%' }}>
        {/* Header */}
        <div style={{ padding:'16px 16px 12px',borderBottom:'1px solid #f1f5f9' }}>
          <div style={{ display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:'12px' }}>
            <span style={{ fontWeight:'800',fontSize:'16px',color:'#0f172a' }}>💬 Intern Chat</span>
            <button onClick={()=>setShowNewChannel('general')}
              style={{ width:'28px',height:'28px',borderRadius:'8px',background:'#f0fdf4',border:'1px solid #bbf7d0',cursor:'pointer',color:'#059669',fontSize:'18px',display:'flex',alignItems:'center',justifyContent:'center',fontWeight:'700' }}>+</button>
          </div>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 Søk kanaler..."
            style={{ width:'100%',padding:'8px 12px',background:'#f8fafc',border:'1px solid #f1f5f9',borderRadius:'10px',color:'#0f172a',fontSize:'13px',outline:'none',boxSizing:'border-box' }} />
        </div>

        {/* Channel list */}
        <div style={{ flex:1,overflowY:'auto',padding:'12px' }}>
          {/* Project sections */}
          {projects.filter(p=>projectChannels[p.id]?.length>0||!search).map(p=>(
            projectChannels[p.id]?.length>0&&(
              <ProjectSection key={p.id} projectId={p.id} label={p.name} chs={projectChannels[p.id]||[]} />
            )
          ))}

          {/* General channels */}
          {(generalChannels.length>0||!search)&&(
            <ProjectSection projectId="general" label="Generelt" chs={generalChannels} />
          )}

          {/* Direct messages */}
          {directChannels.length>0&&(
            <ProjectSection projectId="direct" label="Direkte meldinger" chs={directChannels} />
          )}

          {channels.length===0&&(
            <div style={{ textAlign:'center',padding:'32px 16px',color:'#94a3b8',fontSize:'13px' }}>
              <div style={{ fontSize:'32px',marginBottom:'8px' }}>💬</div>
              Ingen kanaler ennå.<br/>Opprett din første!
            </div>
          )}
        </div>

        {/* User footer */}
        <div style={{ padding:'12px 16px',borderTop:'1px solid #f1f5f9',display:'flex',alignItems:'center',gap:'10px' }}>
          <div style={{ position:'relative' }}>
            <ChatAvatar name={user?.email} size={32} />
            <div style={{ position:'absolute',bottom:0,right:0,width:'10px',height:'10px',borderRadius:'50%',background:'#22c55e',border:'2px solid white' }}/>
          </div>
          <div style={{ flex:1,minWidth:0 }}>
            <div style={{ fontSize:'12px',fontWeight:'600',color:'#0f172a',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{displayName}</div>
            <div style={{ fontSize:'10px',color:'#22c55e',fontWeight:'600' }}>● Online</div>
          </div>
        </div>
      </div>

      {/* MAIN AREA */}
      {selectedChannel ? (
        <ChatWindow
          channel={selectedChannel}
          user={user}
          employees={employees}
          members={members.filter(m=>m.channel_id===selectedChannel.id)}
          projects={projects}
          onRefresh={load}
        />
      ) : (
        <div style={{ flex:1,display:'flex',alignItems:'center',justifyContent:'center',background:'#f8fafc' }}>
          <div style={{ textAlign:'center' }}>
            <div style={{ width:'80px',height:'80px',borderRadius:'24px',background:'#f0fdf4',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'36px',margin:'0 auto 20px',border:'1px solid #bbf7d0' }}>💬</div>
            <h2 style={{ margin:'0 0 8px',color:'#0f172a',fontSize:'20px',fontWeight:'700' }}>Velkommen til Intern Chat</h2>
            <p style={{ margin:'0 0 24px',color:'#64748b',fontSize:'14px' }}>Velg en kanal fra listen, eller opprett en ny</p>
            <button onClick={()=>setShowNewChannel('general')}
              style={{ padding:'11px 22px',background:'#059669',color:'white',border:'none',borderRadius:'12px',cursor:'pointer',fontSize:'14px',fontWeight:'700' }}>+ Ny kanal</button>
          </div>
        </div>
      )}

      {showNewChannel&&(
        <NewChannelModal
          user={user} employees={employees} projects={projects}
          defaultProjectId={typeof showNewChannel==='string'&&showNewChannel!=='general'?showNewChannel:null}
          onClose={()=>setShowNewChannel(false)}
          onSaved={(ch)=>{ setShowNewChannel(false); load(); setSelectedChannel(ch) }}
        />
      )}
    </div>
  )
}

function ChatWindow({ channel, user, employees, members, projects, onRefresh }) {
  const [messages, setMessages] = useState([])
  const [input, setInput] = useState('')
  const [loading, setLoading] = useState(true)
  const [sending, setSending] = useState(false)
  const [search, setSearch] = useState('')
  const [showSearch, setShowSearch] = useState(false)
  const [showMembers, setShowMembers] = useState(false)
  const [showPinned, setShowPinned] = useState(false)
  const [mentionSuggestions, setMentionSuggestions] = useState([])
  const messagesEndRef = React.useRef(null)
  const fileInputRef = React.useRef(null)
  const proj = projects.find(p=>p.id===channel.project_id)

  const loadMessages = async () => {
    const { data } = await supabase.from('chat_messages').select('*')
      .eq('channel_id',channel.id).is('deleted_at',null).order('created_at')
    setMessages(data||[])
    setLoading(false)
    if (user?.id) await supabase.from('chat_members').update({last_read_at:new Date().toISOString()}).eq('channel_id',channel.id).eq('user_id',user.id)
  }

  useEffect(()=>{ setLoading(true); loadMessages() },[channel.id])
  useEffect(()=>{ messagesEndRef.current?.scrollIntoView({behavior:'smooth'}) },[messages])

  useEffect(()=>{
    const sub = supabase.channel(`chat-win-${channel.id}`)
      .on('postgres_changes',{event:'*',schema:'public',table:'chat_messages',filter:`channel_id=eq.${channel.id}`},()=>loadMessages())
      .subscribe()
    return ()=>supabase.removeChannel(sub)
  },[channel.id])

  const getSenderName = (id) => {
    if (id===user?.id) return 'Meg'
    const emp=employees.find(e=>e.id===id)
    return emp?`${emp.first_name} ${emp.last_name}`:'Ukjent'
  }

  const handleInput = (val) => {
    setInput(val)
    const atIdx=val.lastIndexOf('@')
    if (atIdx>=0) {
      const q=val.slice(atIdx+1).toLowerCase()
      setMentionSuggestions(employees.filter(e=>`${e.first_name} ${e.last_name}`.toLowerCase().includes(q)).slice(0,5))
    } else setMentionSuggestions([])
  }

  const insertMention = (emp) => {
    const atIdx=input.lastIndexOf('@')
    setInput(input.slice(0,atIdx)+`@${emp.first_name} ${emp.last_name} `)
    setMentionSuggestions([])
  }

  const send = async () => {
    if (!input.trim()||sending) return
    setSending(true)
    try {
      const mentionNames=[...input.matchAll(/@([A-ZÆØÅ][a-zæøå]+ [A-ZÆØÅ][a-zæøå]+)/g)].map(m=>m[1])
      const mentionIds=employees.filter(e=>mentionNames.includes(`${e.first_name} ${e.last_name}`)).map(e=>e.id)
      await supabase.from('chat_messages').insert({ channel_id:channel.id, sender_id:user?.id, content:input.trim(), mentions:mentionIds })
      await supabase.from('chat_channels').update({updated_at:new Date().toISOString()}).eq('id',channel.id)
      for (const empId of mentionIds) {
        await supabase.from('notifications').insert({ user_id:empId, title:`Du ble nevnt i #${channel.name}`, message:input.trim().slice(0,80), type:'info', link_page:'chat' })
      }
      setInput('')
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSending(false) }
  }

  const handleFile = async (e) => {
    const file=e.target.files?.[0]; if(!file) return
    setSending(true)
    try {
      const path=`chat/${channel.id}/${Date.now()}_${file.name}`
      const {error:upErr}=await supabase.storage.from('plattform-files').upload(path,file)
      if(upErr) throw upErr
      const {data:{publicUrl}}=supabase.storage.from('plattform-files').getPublicUrl(path)
      await supabase.from('chat_messages').insert({ channel_id:channel.id, sender_id:user?.id, content:'', file_url:publicUrl, file_name:file.name, file_type:file.type })
      await supabase.from('chat_channels').update({updated_at:new Date().toISOString()}).eq('id',channel.id)
    } catch(e) { alert('Opplasting feilet: '+e.message) }
    finally { setSending(false); e.target.value='' }
  }

  const togglePin = async (msg) => {
    await supabase.from('chat_messages').update({is_pinned:!msg.is_pinned}).eq('id',msg.id)
    loadMessages()
  }

  const deleteMsg = async (id) => {
    await supabase.from('chat_messages').update({deleted_at:new Date().toISOString()}).eq('id',id)
    loadMessages()
  }

  const pinnedMsgs = messages.filter(m=>m.is_pinned)
  const displayMsgs = search ? messages.filter(m=>m.content?.toLowerCase().includes(search.toLowerCase())) : messages
  const today = new Date().toISOString().split('T')[0]

  const grouped = displayMsgs.map((msg,i)=>{
    const prev=displayMsgs[i-1]
    const isSame=prev&&prev.sender_id===msg.sender_id&&(new Date(msg.created_at)-new Date(prev.created_at))<300000
    const isNewDay=!prev||msg.created_at.split('T')[0]!==prev.created_at.split('T')[0]
    return {...msg,isSameSender:isSame&&!isNewDay,isNewDay}
  })

  const btnStyle = (active) => ({ padding:'7px 12px',borderRadius:'8px',border:`1px solid ${active?'#059669':'#e2e8f0'}`,background:active?'#f0fdf4':'white',color:active?'#059669':'#64748b',cursor:'pointer',fontSize:'12px',fontWeight:'600' })

  return (
    <div style={{ flex:1,display:'flex',flexDirection:'column',background:'white',height:'100%',overflow:'hidden' }}>
      {/* Header */}
      <div style={{ padding:'14px 20px',borderBottom:'1px solid #f1f5f9',display:'flex',alignItems:'center',justifyContent:'space-between',flexShrink:0 }}>
        <div style={{ display:'flex',alignItems:'center',gap:'12px' }}>
          <div style={{ width:'38px',height:'38px',borderRadius:'10px',background:chatColor(channel.name)+'18',border:`1px solid ${chatColor(channel.name)}30`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:'18px',fontWeight:'700',color:chatColor(channel.name) }}>
            {channel.type==='direct'?'👤':'#'}
          </div>
          <div>
            <div style={{ fontWeight:'700',fontSize:'15px',color:'#0f172a' }}>{channel.name}</div>
            <div style={{ fontSize:'12px',color:'#94a3b8' }}>
              {members.length} medlemmer{proj?` · 🏗️ ${proj.name}`:''}
              {channel.description?` · ${channel.description}`:''}
            </div>
          </div>
        </div>
        <div style={{ display:'flex',gap:'6px' }}>
          {pinnedMsgs.length>0&&<button onClick={()=>setShowPinned(v=>!v)} style={btnStyle(showPinned)}>📌 {pinnedMsgs.length}</button>}
          <button onClick={()=>setShowSearch(v=>!v)} style={btnStyle(showSearch)}>🔍 Søk</button>
          <button onClick={()=>setShowMembers(v=>!v)} style={btnStyle(showMembers)}>👥 {members.length}</button>
        </div>
      </div>

      {/* Pinned */}
      {showPinned&&pinnedMsgs.length>0&&(
        <div style={{ background:'#faf5ff',borderBottom:'1px solid #ddd6fe',padding:'10px 20px' }}>
          <div style={{ fontSize:'12px',fontWeight:'700',color:'#7c3aed',marginBottom:'6px' }}>📌 Pinnede meldinger</div>
          {pinnedMsgs.map(m=>(
            <div key={m.id} style={{ fontSize:'13px',color:'#475569',padding:'4px 0',borderBottom:'1px solid #f3e8ff',display:'flex',justifyContent:'space-between' }}>
              <span><strong style={{ color:'#7c3aed' }}>{getSenderName(m.sender_id)}:</strong> {m.content?.slice(0,80)}</span>
              <button onClick={()=>togglePin(m)} style={{ background:'none',border:'none',cursor:'pointer',color:'#94a3b8',fontSize:'12px' }}>Løsne</button>
            </div>
          ))}
        </div>
      )}

      {/* Search */}
      {showSearch&&(
        <div style={{ padding:'8px 20px',background:'#f8fafc',borderBottom:'1px solid #f1f5f9' }}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Søk i meldinger..." autoFocus
            style={{ width:'100%',padding:'8px 12px',border:'1px solid #e2e8f0',borderRadius:'8px',fontSize:'13px',outline:'none',boxSizing:'border-box' }} />
          {search&&<div style={{ fontSize:'11px',color:'#94a3b8',marginTop:'4px' }}>{displayMsgs.length} treff</div>}
        </div>
      )}

      <div style={{ display:'flex',flex:1,overflow:'hidden' }}>
        {/* Messages */}
        <div style={{ flex:1,overflowY:'auto',padding:'16px 20px',display:'flex',flexDirection:'column',gap:'1px',background:'#f8fafc' }}>
          {loading&&<div style={{ textAlign:'center',color:'#94a3b8',fontSize:'13px',padding:'20px' }}>Laster meldinger...</div>}
          {grouped.map(msg=>{
            const isOwn=msg.sender_id===user?.id
            const senderName=getSenderName(msg.sender_id)
            const isImage=msg.file_type?.startsWith('image/')
            const msgDate=msg.created_at.split('T')[0]
            return (
              <React.Fragment key={msg.id}>
                {msg.isNewDay&&(
                  <div style={{ display:'flex',alignItems:'center',gap:'10px',margin:'14px 0' }}>
                    <div style={{ flex:1,height:'1px',background:'#e2e8f0' }}/>
                    <span style={{ fontSize:'11px',fontWeight:'600',color:'#94a3b8',whiteSpace:'nowrap',background:'#f8fafc',padding:'0 8px' }}>
                      {msgDate===today?'I dag':new Date(msgDate+'T12:00:00').toLocaleDateString('nb-NO',{weekday:'long',day:'numeric',month:'long'})}
                    </span>
                    <div style={{ flex:1,height:'1px',background:'#e2e8f0' }}/>
                  </div>
                )}
                <div style={{ display:'flex',gap:'10px',padding:'3px 0',borderRadius:'10px' }}
                  onMouseEnter={e=>{e.currentTarget.style.background='#f1f5f9';e.currentTarget.querySelector('.msgact')&&(e.currentTarget.querySelector('.msgact').style.opacity='1')}}
                  onMouseLeave={e=>{e.currentTarget.style.background='transparent';e.currentTarget.querySelector('.msgact')&&(e.currentTarget.querySelector('.msgact').style.opacity='0')}}>
                  {!msg.isSameSender
                    ? <ChatAvatar name={senderName} size={34} />
                    : <div style={{ width:34 }}/>
                  }
                  <div style={{ flex:1,minWidth:0 }}>
                    {!msg.isSameSender&&(
                      <div style={{ display:'flex',alignItems:'baseline',gap:'8px',marginBottom:'4px' }}>
                        <span style={{ fontWeight:'700',fontSize:'13px',color:isOwn?'#059669':'#0f172a' }}>{senderName}</span>
                        <span style={{ fontSize:'11px',color:'#94a3b8' }}>{fmtChatTime(msg.created_at)}</span>
                        {msg.is_pinned&&<span style={{ fontSize:'11px',color:'#7c3aed' }}>📌</span>}
                      </div>
                    )}
                    {msg.content&&(
                      <div style={{ fontSize:'14px',color:'#0f172a',lineHeight:1.55,wordBreak:'break-word' }}>
                        {msg.content.split(/(@[A-ZÆØÅ][a-zæøå]+ [A-ZÆØÅ][a-zæøå]+)/g).map((part,i)=>
                          part.startsWith('@')
                            ? <span key={i} style={{ background:'#eff6ff',color:'#2563eb',borderRadius:'4px',padding:'1px 4px',fontWeight:'700',fontSize:'13px' }}>{part}</span>
                            : <span key={i}>{part}</span>
                        )}
                      </div>
                    )}
                    {msg.file_url&&(
                      <div style={{ marginTop:'6px' }}>
                        {isImage
                          ? <img src={msg.file_url} alt={msg.file_name} style={{ maxWidth:'320px',maxHeight:'220px',borderRadius:'10px',border:'1px solid #f1f5f9',cursor:'pointer',display:'block' }} onClick={()=>window.open(msg.file_url,'_blank')} />
                          : <a href={msg.file_url} target="_blank" rel="noreferrer" style={{ display:'inline-flex',alignItems:'center',gap:'8px',background:'white',border:'1px solid #f1f5f9',borderRadius:'10px',padding:'8px 14px',color:'#2563eb',textDecoration:'none',fontSize:'13px',fontWeight:'600' }}>📎 {msg.file_name}</a>
                        }
                      </div>
                    )}
                  </div>
                  <div className="msgact" style={{ display:'flex',gap:'4px',opacity:0,transition:'opacity 0.15s',flexShrink:0,alignItems:'flex-start' }}>
                    <button onClick={()=>togglePin(msg)} style={{ padding:'4px 8px',borderRadius:'6px',border:'1px solid #e2e8f0',background:'white',cursor:'pointer',fontSize:'11px' }}>{msg.is_pinned?'📌':'📍'}</button>
                    {isOwn&&<button onClick={()=>deleteMsg(msg.id)} style={{ padding:'4px 8px',borderRadius:'6px',border:'1px solid #fecaca',background:'white',cursor:'pointer',fontSize:'11px',color:'#dc2626' }}>🗑️</button>}
                  </div>
                </div>
              </React.Fragment>
            )
          })}
          {messages.length===0&&!loading&&(
            <div style={{ textAlign:'center',padding:'60px 20px',color:'#94a3b8' }}>
              <div style={{ fontSize:'36px',marginBottom:'12px' }}>💬</div>
              <div style={{ fontSize:'14px',fontWeight:'600' }}>Ingen meldinger ennå</div>
              <div style={{ fontSize:'13px',marginTop:'4px' }}>Vær den første til å skrive noe!</div>
            </div>
          )}
          <div ref={messagesEndRef}/>
        </div>

        {/* Members panel */}
        {showMembers&&(
          <div style={{ width:'220px',flexShrink:0,borderLeft:'1px solid #f1f5f9',background:'white',padding:'16px',overflowY:'auto' }}>
            <div style={{ fontSize:'13px',fontWeight:'700',color:'#0f172a',marginBottom:'12px' }}>👥 Medlemmer ({members.length})</div>
            {members.map(m=>{
              const emp=employees.find(e=>e.id===m.employee_id)
              const name=emp?`${emp.first_name} ${emp.last_name}`:'Ukjent'
              return (
                <div key={m.id} style={{ display:'flex',alignItems:'center',gap:'8px',padding:'7px 0',borderBottom:'1px solid #f8fafc' }}>
                  <ChatAvatar name={name} size={28} />
                  <div style={{ flex:1,minWidth:0 }}>
                    <div style={{ fontSize:'12px',fontWeight:'600',color:'#0f172a',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{name}</div>
                    {m.role==='admin'&&<div style={{ fontSize:'10px',color:'#7c3aed',fontWeight:'700' }}>Admin</div>}
                  </div>
                </div>
              )
            })}
          </div>
        )}
      </div>

      {/* Input */}
      <div style={{ padding:'12px 20px',borderTop:'1px solid #f1f5f9',background:'white',flexShrink:0,position:'relative' }}>
        {mentionSuggestions.length>0&&(
          <div style={{ position:'absolute',bottom:'100%',left:'20px',background:'white',border:'1px solid #e2e8f0',borderRadius:'12px',boxShadow:'0 8px 24px rgba(0,0,0,0.12)',padding:'6px',zIndex:50,minWidth:'220px' }}>
            {mentionSuggestions.map(emp=>(
              <div key={emp.id} onClick={()=>insertMention(emp)}
                style={{ display:'flex',alignItems:'center',gap:'8px',padding:'8px 10px',borderRadius:'8px',cursor:'pointer' }}
                onMouseEnter={e=>e.currentTarget.style.background='#f8fafc'} onMouseLeave={e=>e.currentTarget.style.background='transparent'}>
                <ChatAvatar name={`${emp.first_name} ${emp.last_name}`} size={24} />
                <span style={{ fontSize:'13px',fontWeight:'600',color:'#0f172a' }}>{emp.first_name} {emp.last_name}</span>
              </div>
            ))}
          </div>
        )}
        <div style={{ display:'flex',gap:'8px',alignItems:'flex-end' }}>
          <button onClick={()=>fileInputRef.current?.click()} style={{ padding:'10px',borderRadius:'10px',border:'1px solid #e2e8f0',background:'#f8fafc',cursor:'pointer',color:'#64748b',fontSize:'16px',flexShrink:0 }}>📎</button>
          <input ref={fileInputRef} type="file" style={{ display:'none' }} onChange={handleFile} accept="image/*,.pdf,.doc,.docx,.xlsx" />
          <textarea value={input} onChange={e=>handleInput(e.target.value)}
            onKeyDown={e=>{ if(e.key==='Enter'&&!e.shiftKey&&mentionSuggestions.length===0){e.preventDefault();send()} }}
            placeholder={`Skriv til #${channel.name}… (@ for å nevne)`}
            rows={1}
            style={{ flex:1,padding:'10px 14px',border:'1px solid #e2e8f0',borderRadius:'10px',fontSize:'14px',outline:'none',resize:'none',fontFamily:'system-ui,sans-serif',lineHeight:1.5,background:'#f8fafc' }}
          />
          <button onClick={send} disabled={sending||!input.trim()}
            style={{ padding:'10px 16px',borderRadius:'10px',background:sending||!input.trim()?'#e2e8f0':'#059669',color:sending||!input.trim()?'#94a3b8':'white',border:'none',cursor:sending||!input.trim()?'not-allowed':'pointer',fontSize:'20px',flexShrink:0 }}>
            ➤
          </button>
        </div>
        <div style={{ fontSize:'11px',color:'#cbd5e1',marginTop:'5px' }}>Enter = send · Shift+Enter = ny linje · @ = nevn</div>
      </div>
    </div>
  )
}

function NewChannelModal({ user, employees, projects, defaultProjectId, onClose, onSaved }) {
  const [form, setForm] = useState({ name:'', description:'', type:'group', project_id:defaultProjectId||'', is_private:false })
  const [selectedMembers, setSelectedMembers] = useState([])
  const [saving, setSaving] = useState(false)
  const set = (k,v) => setForm(f=>({...f,[k]:v}))

  const handleSave = async () => {
    if (!form.name.trim()) return alert('Kanalnavn er påkrevd')
    setSaving(true)
    try {
      const { data:ch, error } = await supabase.from('chat_channels').insert({
        name:form.name.trim().replace(/\s/g,'-').toLowerCase(),
        description:form.description||null, type:form.type,
        project_id:form.project_id||null, is_private:form.is_private, created_by:user?.id
      }).select().single()
      if (error) throw error
      const inserts=[{ channel_id:ch.id, user_id:user?.id, role:'admin' }]
      for (const empId of selectedMembers) {
        inserts.push({ channel_id:ch.id, user_id:empId, employee_id:empId, role:'member' })
        await supabase.from('notifications').insert({ user_id:empId, title:`Du ble lagt til i #${ch.name}`, message:form.description||form.name, type:'info', link_page:'chat' })
      }
      await supabase.from('chat_members').insert(inserts)
      onSaved(ch)
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed',inset:0,zIndex:110,display:'flex',alignItems:'center',justifyContent:'center',padding:'16px' }}>
      <div style={{ position:'absolute',inset:0,background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative',background:'white',borderRadius:'20px',width:'100%',maxWidth:'520px',maxHeight:'90vh',display:'flex',flexDirection:'column',boxShadow:'0 20px 60px rgba(0,0,0,0.2)',fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding:'20px 24px',borderBottom:'1px solid #f1f5f9',display:'flex',justifyContent:'space-between',alignItems:'center',flexShrink:0 }}>
          <h2 style={{ margin:0,fontSize:'18px',fontWeight:'700',color:'#0f172a' }}>💬 Ny kanal</h2>
          <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
            <button type="button" onClick={onClose} style={{ padding:'8px 16px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleSave} disabled={saving||!form.name.trim()} style={{ padding:'8px 20px', background:saving||!form.name.trim()?'#94a3b8':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize:'14px', fontWeight:'700' }}>{saving?'Oppretter...':'Opprett kanal'}</button>
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8', marginLeft:'4px' }}>×</button>
          </div>
        </div>
        <div style={{ overflowY:'auto',flex:1,padding:'20px 24px',display:'flex',flexDirection:'column',gap:'14px' }}>
          <div>
            <label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'8px' }}>Type</label>
            <div style={{ display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:'8px' }}>
              {[['group','👥','Gruppe'],['project','🏗️','Prosjekt'],['direct','👤','Direkte']].map(([v,e,l])=>(
                <button key={v} onClick={()=>set('type',v)}
                  style={{ padding:'10px',borderRadius:'10px',border:`2px solid ${form.type===v?'#059669':'#e2e8f0'}`,background:form.type===v?'#f0fdf4':'white',cursor:'pointer',textAlign:'center' }}>
                  <div style={{ fontSize:'20px',marginBottom:'4px' }}>{e}</div>
                  <div style={{ fontSize:'12px',fontWeight:'700',color:form.type===v?'#059669':'#0f172a' }}>{l}</div>
                </button>
              ))}
            </div>
          </div>
          <div>
            <label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'6px' }}>Kanalnavn *</label>
            <input value={form.name} onChange={e=>set('name',e.target.value)} placeholder="f.eks. prosjektledelse, alle-på-prosjektet" style={{ width:'100%',padding:'9px 12px',border:'1px solid #e2e8f0',borderRadius:'10px',fontSize:'14px',outline:'none',boxSizing:'border-box' }} />
          </div>
          <div>
            <label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'6px' }}>Beskrivelse</label>
            <input value={form.description} onChange={e=>set('description',e.target.value)} placeholder="Hva er denne kanalen til?" style={{ width:'100%',padding:'9px 12px',border:'1px solid #e2e8f0',borderRadius:'10px',fontSize:'14px',outline:'none',boxSizing:'border-box' }} />
          </div>
          <div>
            <label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'6px' }}>Knytt til prosjekt</label>
            <select value={form.project_id} onChange={e=>set('project_id',e.target.value)} style={{ width:'100%',padding:'9px 12px',border:'1px solid #e2e8f0',borderRadius:'10px',fontSize:'14px',outline:'none',boxSizing:'border-box',background:'white' }}>
              <option value="">Ingen (generell kanal)</option>
              {projectOptions(projects).map(p => <option key={p.id} value={p.id}>{'  '.repeat(p._depth)}{p._depth > 0 ? '└ ' : ''}{p.name}{p.project_number ? ` (${p.project_number})` : ''}</option>)}
            </select>
          </div>
          <label style={{ display:'flex',alignItems:'center',gap:'8px',cursor:'pointer',fontSize:'13px',fontWeight:'600',color:'#374151' }}>
            <input type="checkbox" checked={form.is_private} onChange={e=>set('is_private',e.target.checked)} style={{ width:'16px',height:'16px',accentColor:'#059669' }} />
            🔒 Privat kanal
          </label>
          <div>
            <label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'8px' }}>Legg til medlemmer</label>
            <div style={{ display:'flex',flexWrap:'wrap',gap:'6px',maxHeight:'140px',overflowY:'auto' }}>
              {employees.map(emp=>{
                const isSel=selectedMembers.includes(emp.id)
                return (
                  <button key={emp.id} onClick={()=>setSelectedMembers(s=>isSel?s.filter(x=>x!==emp.id):[...s,emp.id])}
                    style={{ display:'flex',alignItems:'center',gap:'5px',padding:'5px 10px',borderRadius:'999px',border:`2px solid ${isSel?'#059669':'#e2e8f0'}`,background:isSel?'#f0fdf4':'white',cursor:'pointer',fontSize:'12px',fontWeight:'600',color:isSel?'#059669':'#64748b' }}>
                    <ChatAvatar name={`${emp.first_name} ${emp.last_name}`} size={18} />
                    {emp.first_name} {emp.last_name}
                  </button>
                )
              })}
            </div>
          </div>
        </div>

      </div>
    </div>
  )
}

// ─── END INTERN CHAT MODULE ───────────────────────────────────────────────────


// ─── KUNDER MODULE ────────────────────────────────────────────────────────────

const KUNDE_TYPE = {
  bedrift:  { label: 'Bedrift',      emoji: '🏢', color: '#2563eb', bg: '#eff6ff' },
  privat:   { label: 'Privat',       emoji: '👤', color: '#7c3aed', bg: '#f5f3ff' },
  offentlig:{ label: 'Offentlig',    emoji: '🏛️', color: '#0891b2', bg: '#ecfeff' },
  borettslag:{ label:'Borettslag',   emoji: '🏘️', color: '#059669', bg: '#f0fdf4' },
  ue:       { label: 'Underleverandør', emoji: '🤝', color: '#d97706', bg: '#fffbeb' },
}

const kundeInp = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', fontFamily:'system-ui,sans-serif' }

function KunderPage() {
  const { user } = useAuth()
  const confirm = useConfirm()
  const [kunder, setKunder] = useState([])
  const [prosjekter, setProsjekter] = useState([])
  const [tilbud, setTilbud] = useState([])
  const [fakturaer, setFakturaer] = useState([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [filterType, setFilterType] = useState('alle')
  const [selected, setSelected] = useState(null)
  const [showNew, setShowNew] = useState(false)
  const [showImport, setShowImport] = useState(false)
  const [importData, setImportData] = useState(null)
  const [importErrors, setImportErrors] = useState([])
  const [importing, setImporting] = useState(false)
  const csvInputRef = React.useRef()

  const exportCSV = () => {
    const headers = ['Navn','Type','Org.nr','E-post','Telefon','Faktura e-post','Adresse','Postnr','By','Merknad']
    const rows = kunder.map(k => [k.name, k.type, k.orgnr, k.email, k.phone, k.invoice_email, k.address, k.postal_code, k.city, k.notes].map(v => `"${(v||'').replace(/"/g,'""')}"`).join(';'))
    const csv = '\uFEFF' + [headers.join(';'), ...rows].join('\n')
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a'); a.href = url; a.download = `Kunderegister-${new Date().toISOString().split('T')[0]}.csv`; a.click()
    URL.revokeObjectURL(url)
  }

  const handleImportFile = (e) => {
    const file = e.target.files?.[0]
    if (!file) return
    const reader = new FileReader()
    reader.onload = (ev) => {
      const text = ev.target.result
      const sep = text.includes(';') ? ';' : ','
      const lines = text.split('\n').map(l => l.split(sep).map(c => c.replace(/^"|"$/g, '').replace(/""/g, '"').trim()))
      if (lines.length < 2) { alert('Filen er tom eller har feil format'); return }
      const headers = lines[0].map(h => h.toLowerCase())
      const nameIdx = headers.findIndex(h => h.includes('navn') || h === 'name')
      if (nameIdx === -1) { alert('Fant ikke Navn-kolonne i CSV-filen'); return }
      const fieldMap = {
        name: nameIdx, type: headers.findIndex(h => h.includes('type')),
        orgnr: headers.findIndex(h => h.includes('org')),
        email: headers.findIndex(h => (h.includes('e-post') || h.includes('email')) && !h.includes('faktura')),
        phone: headers.findIndex(h => h.includes('telefon') || h.includes('phone') || h.includes('tlf')),
        invoice_email: headers.findIndex(h => h.includes('faktura')),
        address: headers.findIndex(h => h.includes('adresse') || h.includes('address')),
        postal_code: headers.findIndex(h => h.includes('postnr') || h.includes('postal')),
        city: headers.findIndex(h => h.includes('by') || h.includes('sted') || h.includes('city')),
        notes: headers.findIndex(h => h.includes('merknad') || h.includes('notat')),
      }
      const rows = lines.slice(1).filter(l => l[nameIdx]?.trim()).map(l => {
        const row = {}; Object.entries(fieldMap).forEach(([key, idx]) => { if (idx >= 0) row[key] = l[idx] || '' }); return row
      })
      const errors = []
      rows.forEach((r, i) => {
        if (kunder.find(k => k.name?.toLowerCase() === r.name?.toLowerCase())) errors.push({ row: i+2, msg: `"${r.name}" finnes allerede` })
        if (r.orgnr && kunder.find(k => k.orgnr && k.orgnr === r.orgnr)) errors.push({ row: i+2, msg: `Org.nr ${r.orgnr} finnes allerede` })
      })
      setImportData(rows); setImportErrors(errors); setShowImport(true)
    }
    reader.readAsText(file, 'UTF-8'); e.target.value = ''
  }

  const confirmImport = async () => {
    if (!importData?.length) return; setImporting(true)
    try {
      const clean = importData.filter(r => r.name?.trim()).map(r => ({ name: r.name?.trim(), type: r.type || 'bedrift', orgnr: r.orgnr || null, email: r.email || null, phone: r.phone || null, invoice_email: r.invoice_email || null, address: r.address || null, postal_code: r.postal_code || null, city: r.city || null, notes: r.notes || null, created_by: user?.id }))
      const { error } = await supabase.from('customers').insert(clean)
      if (error) throw error; setShowImport(false); setImportData(null); setImportErrors([]); load()
    } catch(e) { alert('Feil ved import: ' + e.message) } finally { setImporting(false) }
  }

  const load = async () => {
    setLoading(true)
    try {
      const [k, p, q, inv] = await Promise.all([
        supabase.from('customers').select('*').order('name').then(r => r.data || []),
        supabase.from('projects').select('id,name,status,customer_id').order('name').then(r => r.data || []),
        supabase.from('quotes').select('id,title,status,total_amount,customer_id,created_at').order('created_at',{ascending:false}).then(r => r.data || []),
        supabase.from('invoices').select('id,title,status,total_amount,customer_id,created_at,due_date').order('created_at',{ascending:false}).then(r => r.data || []),
      ])
      setKunder(k); setProsjekter(p); setTilbud(q); setFakturaer(inv)
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }

  useEffect(() => { load() }, [])

  const filtered = kunder.filter(k => {
    if (filterType !== 'alle' && k.type !== filterType) return false
    if (search && ![k.name, k.email, k.phone, k.orgnr, k.city].some(v => v?.toLowerCase().includes(search.toLowerCase()))) return false
    return true
  })

  const handleDelete = async (kunde) => {
    const ok = await confirm({ message: `Slett ${kunde.name}?`, subMessage: 'Kunden og all tilhørende informasjon slettes permanent.', danger: true })
    if (!ok) return
    try {
      await supabase.from('customers').delete().eq('id', kunde.id)
      await load()
    } catch(e) { alert('Feil: ' + e.message) }
  }

  if (loading) return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center', minHeight:'60vh', fontFamily:'system-ui,sans-serif' }}>
      <div style={{ textAlign:'center' }}>
        <div style={{ width:'36px', height:'36px', border:'3px solid #e2e8f0', borderTop:'3px solid #059669', borderRadius:'50%', margin:'0 auto 12px', animation:'spin 1s linear infinite' }}/>
        <p style={{ color:'#94a3b8', fontSize:'14px' }}>Laster kunder...</p>
      </div>
    </div>
  )

  if (selected) return (
    <KundeDetaljer
      kunde={selected}
      prosjekter={prosjekter.filter(p => p.customer_id === selected.id)}
      tilbud={tilbud.filter(t => t.customer_id === selected.id)}
      fakturaer={fakturaer.filter(f => f.customer_id === selected.id)}
      user={user}
      onBack={() => { setSelected(null); load() }}
      onRefresh={load}
    />
  )

  return (
    <div style={{ fontFamily:'system-ui,sans-serif' }}>
      {/* Header */}
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding:'20px 32px', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
        <div>
          <h1 style={{ margin:0, fontSize:'22px', fontWeight:'bold', color:'#0f172a' }}>Kundeoversikt</h1>
          <p style={{ margin:'3px 0 0', fontSize:'13px', color:'#64748b' }}>{kunder.length} registrerte kunder</p>
        </div>
        <div style={{ display:'flex', gap:'8px' }}>
          <button onClick={exportCSV} style={{ padding:'10px 16px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'13px', fontWeight:'600', color:'#374151' }}>
            Eksporter CSV
          </button>
          <label style={{ padding:'10px 16px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'13px', fontWeight:'600', color:'#374151', display:'flex', alignItems:'center' }}>
            Importer CSV
            <input ref={csvInputRef} type="file" accept=".csv,.txt" style={{ display:'none' }} onChange={handleImportFile} />
          </label>
          <button onClick={() => setShowNew(true)}
            style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding:'10px 20px', fontSize:'14px', fontWeight:'700', cursor:'pointer' }}>
            + Ny kunde
          </button>
        </div>
      </div>

      {/* Stats */}
      <div style={{ background:'white', borderBottom:'1px solid #f1f5f9', padding:'12px 32px', display:'flex', gap:'24px' }}>
        {Object.entries(KUNDE_TYPE).map(([key, cfg]) => {
          const count = kunder.filter(k => k.type === key).length
          return (
            <button key={key} onClick={() => setFilterType(filterType === key ? 'alle' : key)}
              style={{ display:'flex', alignItems:'center', gap:'8px', background:'none', border:'none', cursor:'pointer', padding:'6px 12px', borderRadius:'10px',
                background: filterType === key ? cfg.bg : 'transparent',
                color: filterType === key ? cfg.color : '#64748b' }}>
              <span style={{ fontSize:'16px' }}>{cfg.emoji}</span>
              <span style={{ fontSize:'13px', fontWeight:'600' }}>{cfg.label}</span>
              <span style={{ background: filterType === key ? cfg.color : '#e2e8f0', color: filterType === key ? 'white' : '#64748b',
                borderRadius:'999px', fontSize:'11px', fontWeight:'700', padding:'1px 7px' }}>{count}</span>
            </button>
          )
        })}
      </div>

      {/* Search */}
      <div style={{ padding:'16px 32px', background:'white', borderBottom:'1px solid #f1f5f9', display:'flex', gap:'10px', alignItems:'center' }}>
        <div style={{ position:'relative', flex:1, maxWidth:'360px' }}>
          <span style={{ position:'absolute', left:'10px', top:'50%', transform:'translateY(-50%)', color:'#94a3b8', fontSize:'14px' }}>🔍</span>
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Søk på navn, e-post, telefon, orgnr..."
            style={{ ...kundeInp, paddingLeft:'34px' }} />
        </div>
        {(search || filterType !== 'alle') && (
          <button onClick={() => { setSearch(''); setFilterType('alle') }}
            style={{ background:'#f1f5f9', border:'none', borderRadius:'8px', padding:'9px 14px', fontSize:'13px', cursor:'pointer', color:'#64748b' }}>
            Nullstill
          </button>
        )}
        <span style={{ marginLeft:'auto', fontSize:'13px', color:'#94a3b8' }}>{filtered.length} kunder</span>
      </div>

      {/* Customer list */}
      <div style={{ padding:'20px 32px' }}>
        {filtered.length === 0 ? (
          <div style={{ textAlign:'center', padding:'60px 20px', background:'white', borderRadius:'16px', border:'1px solid #f1f5f9' }}>
            <div style={{ fontSize:'48px', marginBottom:'12px' }}>🏢</div>
            <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>{search ? 'Ingen kunder funnet' : 'Ingen kunder ennå'}</h3>
            <p style={{ margin:'0 0 20px', color:'#94a3b8', fontSize:'14px' }}>{search ? 'Prøv et annet søkeord' : 'Registrer din første kunde'}</p>
            {!search && <button onClick={() => setShowNew(true)} style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding:'11px 22px', cursor:'pointer', fontSize:'14px', fontWeight:'700' }}>+ Ny kunde</button>}
          </div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            {filtered.map(kunde => {
              const type = KUNDE_TYPE[kunde.type] || KUNDE_TYPE.bedrift
              const antallProsjekter = prosjekter.filter(p => p.customer_id === kunde.id).length
              return (
                <div key={kunde.id}
                  style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'16px 20px', display:'flex', alignItems:'center', gap:'16px', cursor:'pointer', transition:'box-shadow 0.15s' }}
                  onClick={() => setSelected(kunde)}
                  onMouseEnter={e => e.currentTarget.style.boxShadow = '0 4px 16px rgba(0,0,0,0.08)'}
                  onMouseLeave={e => e.currentTarget.style.boxShadow = 'none'}>
                  {/* Avatar */}
                  <div style={{ width:'44px', height:'44px', borderRadius:'12px', background:type.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px', flexShrink:0 }}>
                    {type.emoji}
                  </div>
                  {/* Info */}
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', alignItems:'center', gap:'10px', marginBottom:'4px' }}>
                      <span style={{ fontWeight:'700', fontSize:'15px', color:'#0f172a' }}>{kunde.name}</span>
                      <span style={{ background:type.bg, color:type.color, borderRadius:'999px', fontSize:'11px', fontWeight:'700', padding:'2px 8px' }}>{type.emoji} {type.label}</span>
                    </div>
                    <div style={{ display:'flex', gap:'16px', fontSize:'13px', color:'#64748b', flexWrap:'wrap' }}>
                      {kunde.orgnr && <span>Org: {kunde.orgnr}</span>}
                      {kunde.email && <span>✉️ {kunde.email}</span>}
                      {kunde.phone && <span>📞 {kunde.phone}</span>}
                      {kunde.city && <span>📍 {kunde.city}</span>}
                    </div>
                  </div>
                  {/* Prosjekter */}
                  {antallProsjekter > 0 && (
                    <div style={{ textAlign:'center', flexShrink:0 }}>
                      <div style={{ fontSize:'18px', fontWeight:'800', color:'#059669' }}>{antallProsjekter}</div>
                      <div style={{ fontSize:'11px', color:'#94a3b8' }}>prosjekt{antallProsjekter !== 1 ? 'er' : ''}</div>
                    </div>
                  )}
                  {/* Actions */}
                  <div style={{ display:'flex', gap:'6px', flexShrink:0 }} onClick={e => e.stopPropagation()}>
                    <button onClick={() => setSelected(kunde)}
                      style={{ background:'#f0fdf4', color:'#059669', border:'1px solid #bbf7d0', borderRadius:'8px', padding:'7px 14px', cursor:'pointer', fontSize:'13px', fontWeight:'600' }}>
                      Åpne
                    </button>
                    <button onClick={() => handleDelete(kunde)}
                      style={{ background:'#fef2f2', color:'#dc2626', border:'none', borderRadius:'8px', padding:'7px 10px', cursor:'pointer', fontSize:'14px' }}>
                      🗑️
                    </button>
                  </div>
                </div>
              )
            })}
          </div>
        )}
      </div>

      {/* Import-modal */}
      {showImport && importData && (
        <>
          <div onClick={() => { setShowImport(false); setImportData(null); setImportErrors([]) }} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.45)', zIndex:100 }} />
          <div style={{ position:'fixed', top:'50%', left:'50%', transform:'translate(-50%,-50%)', background:'white', borderRadius:'20px', width:'min(640px, calc(100vw - 32px))', maxHeight:'90vh', display:'flex', flexDirection:'column', zIndex:101, boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
            <div style={{ padding:'18px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
              <h2 style={{ margin:0, fontSize:'17px', fontWeight:'700', color:'#0f172a' }}>Importer kunder fra CSV</h2>
              <button onClick={() => { setShowImport(false); setImportData(null) }} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
            </div>
            <div style={{ padding:'20px 24px', overflowY:'auto', flex:1 }}>
              <div style={{ background:'#ecfdf5', borderRadius:'10px', padding:'12px 16px', marginBottom:'16px', border:'1px solid #a7f3d0' }}>
                <span style={{ fontSize:'13px', color:'#059669', fontWeight:'600' }}>{importData.length} kunder funnet i filen</span>
              </div>

              {importErrors.length > 0 && (
                <div style={{ background:'#fffbeb', borderRadius:'10px', padding:'12px 16px', marginBottom:'16px', border:'1px solid #fde68a' }}>
                  <div style={{ fontSize:'13px', fontWeight:'700', color:'#d97706', marginBottom:'6px' }}>Mulige duplikater ({importErrors.length})</div>
                  {importErrors.slice(0, 5).map((err, i) => (
                    <div key={i} style={{ fontSize:'12px', color:'#92400e', marginBottom:'2px' }}>Rad {err.row}: {err.msg}</div>
                  ))}
                  {importErrors.length > 5 && <div style={{ fontSize:'12px', color:'#92400e', fontStyle:'italic' }}>+ {importErrors.length - 5} til...</div>}
                </div>
              )}

              {/* Forhåndsvisning */}
              <div style={{ border:'1px solid #f1f5f9', borderRadius:'10px', overflow:'hidden', maxHeight:'300px', overflowY:'auto' }}>
                <table style={{ width:'100%', borderCollapse:'collapse', fontSize:'12px' }}>
                  <thead>
                    <tr style={{ background:'#f8fafc' }}>
                      {['Navn','Type','Org.nr','E-post','Telefon','By'].map(h => <th key={h} style={{ padding:'8px 10px', textAlign:'left', fontWeight:'700', color:'#64748b', borderBottom:'1px solid #f1f5f9', fontSize:'11px' }}>{h}</th>)}
                    </tr>
                  </thead>
                  <tbody>
                    {importData.slice(0, 20).map((r, i) => {
                      const hasDup = importErrors.some(e => e.row === i + 2)
                      return (
                        <tr key={i} style={{ background: hasDup ? '#fffbeb' : i % 2 === 0 ? 'white' : '#fafafa' }}>
                          <td style={{ padding:'6px 10px', fontWeight:'600', color:'#0f172a' }}>{r.name}{hasDup && <span style={{ color:'#d97706', fontSize:'10px', marginLeft:'4px' }}>dup</span>}</td>
                          <td style={{ padding:'6px 10px', color:'#64748b' }}>{r.type || '—'}</td>
                          <td style={{ padding:'6px 10px', color:'#64748b' }}>{r.orgnr || '—'}</td>
                          <td style={{ padding:'6px 10px', color:'#64748b' }}>{r.email || '—'}</td>
                          <td style={{ padding:'6px 10px', color:'#64748b' }}>{r.phone || '—'}</td>
                          <td style={{ padding:'6px 10px', color:'#64748b' }}>{r.city || '—'}</td>
                        </tr>
                      )
                    })}
                  </tbody>
                </table>
                {importData.length > 20 && <div style={{ padding:'8px', textAlign:'center', fontSize:'12px', color:'#94a3b8', background:'#f8fafc' }}>+ {importData.length - 20} rader til...</div>}
              </div>
            </div>
            <div style={{ padding:'16px 24px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
              <span style={{ fontSize:'12px', color:'#94a3b8' }}>{importErrors.length > 0 ? `${importErrors.length} advarsler — duplikater importeres likevel` : 'Ingen duplikater funnet'}</span>
              <div style={{ display:'flex', gap:'10px' }}>
                <button onClick={() => { setShowImport(false); setImportData(null) }} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                <button onClick={confirmImport} disabled={importing} style={{ padding:'10px 24px', background: importing ? '#6ee7b7' : '#059669', color:'white', border:'none', borderRadius:'10px', cursor: importing ? 'not-allowed' : 'pointer', fontSize:'14px', fontWeight:'600' }}>
                  {importing ? 'Importerer...' : `Importer ${importData.length} kunder`}
                </button>
              </div>
            </div>
          </div>
        </>
      )}

      {showNew && <KundeModal user={user} existingKunder={kunder} onClose={() => setShowNew(false)} onSaved={() => { setShowNew(false); load() }} />}
    </div>
  )
}

function KundeDetaljer({ kunde, prosjekter, tilbud = [], fakturaer = [], user, onBack, onRefresh }) {
  const confirm = useConfirm()
  const [editing, setEditing] = useState(false)
  const [kontakter, setKontakter] = useState([])
  const [notater, setNotater] = useState([])
  const [ordrer, setOrdrer] = useState([])
  const [avvik, setAvvik] = useState([])
  const [nyttNotat, setNyttNotat] = useState('')
  const [showNyKontakt, setShowNyKontakt] = useState(false)
  const [loading, setLoading] = useState(true)
  const [activeTab, setActiveTab] = useState('oversikt')
  const type = KUNDE_TYPE[kunde.type] || KUNDE_TYPE.bedrift

  const loadDetails = async () => {
    setLoading(true)
    try {
      const projIds = prosjekter.map(p => p.id)
      const [k, n, ord, avv] = await Promise.all([
        supabase.from('customer_contacts').select('*').eq('customer_id', kunde.id).order('name').then(r => r.data || []),
        supabase.from('customer_notes').select('*').eq('customer_id', kunde.id).order('created_at', {ascending:false}).then(r => r.data || []),
        supabase.from('orders').select('id,title,status,total_amount,customer_id,created_at').eq('customer_id', kunde.id).order('created_at',{ascending:false}).then(r => r.data || []),
        projIds.length > 0
          ? supabase.from('deviations').select('id,title,status,severity,project_id,created_at').in('project_id', projIds).order('created_at',{ascending:false}).then(r => r.data || [])
          : Promise.resolve([]),
      ])
      setKontakter(k); setNotater(n); setOrdrer(ord); setAvvik(avv)
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(() => { loadDetails() }, [])

  const lagreNotat = async () => {
    if (!nyttNotat.trim()) return
    try {
      await supabase.from('customer_notes').insert({ customer_id:kunde.id, content:nyttNotat.trim(), created_by:user?.id })
      setNyttNotat('')
      loadDetails()
    } catch(e) { alert('Feil: ' + e.message) }
  }

  const slettKontakt = async (id) => {
    const ok = await confirm({ message: 'Slett kontaktperson?', danger: true })
    if (!ok) return
    await supabase.from('customer_contacts').delete().eq('id', id)
    loadDetails()
  }

  const slettNotat = async (id) => {
    const ok = await confirm({ message: 'Slett notat?', danger: true })
    if (!ok) return
    await supabase.from('customer_notes').delete().eq('id', id)
    loadDetails()
  }

  // ── Statistikk ──
  const totalFakturert = fakturaer.filter(f => f.status === 'Betalt').reduce((s, f) => s + (f.total_amount || 0), 0)
  const utestaende = fakturaer.filter(f => f.status !== 'Betalt' && f.status !== 'Kansellert').reduce((s, f) => s + (f.total_amount || 0), 0)
  const forfalt = fakturaer.filter(f => f.status !== 'Betalt' && f.due_date && f.due_date < new Date().toISOString().split('T')[0])
  const aktiveTilbud = tilbud.filter(t => t.status === 'Sendt')
  const aksepterteTilbud = tilbud.filter(t => t.status === 'Akseptert')

  // ── Samlet historikk-tidslinje ──
  const buildTimeline = () => {
    const events = []
    prosjekter.forEach(p => events.push({ date: p.created_at || p.start_date || '2020-01-01', type: 'prosjekt', icon: '🏗️', color: '#059669', title: p.name, sub: `Status: ${p.status || 'Aktiv'}` }))
    tilbud.forEach(t => events.push({ date: t.created_at, type: 'tilbud', icon: '📋', color: '#2563eb', title: t.title, sub: `${t.status}${t.total_amount ? ' · ' + Math.round(t.total_amount).toLocaleString('nb-NO') + ' kr' : ''}` }))
    fakturaer.forEach(f => {
      const isOverdue = f.status !== 'Betalt' && f.due_date && f.due_date < new Date().toISOString().split('T')[0]
      events.push({ date: f.created_at, type: 'faktura', icon: '🧾', color: isOverdue ? '#dc2626' : f.status === 'Betalt' ? '#059669' : '#d97706', title: f.title, sub: `${isOverdue ? 'Forfalt' : f.status}${f.total_amount ? ' · ' + Math.round(f.total_amount).toLocaleString('nb-NO') + ' kr' : ''}` })
    })
    ordrer.forEach(o => events.push({ date: o.created_at, type: 'ordre', icon: '📦', color: '#7c3aed', title: o.title, sub: `${o.status || 'Aktiv'}${o.total_amount ? ' · ' + Math.round(o.total_amount).toLocaleString('nb-NO') + ' kr' : ''}` }))
    avvik.forEach(a => {
      const proj = prosjekter.find(p => p.id === a.project_id)
      events.push({ date: a.created_at, type: 'avvik', icon: '⚠️', color: '#ea580c', title: a.title, sub: `${a.severity} · ${a.status}${proj ? ' · ' + proj.name : ''}` })
    })
    notater.forEach(n => events.push({ date: n.created_at, type: 'notat', icon: '📝', color: '#64748b', title: n.content?.slice(0, 80) + (n.content?.length > 80 ? '...' : ''), sub: 'Notat' }))
    return events.sort((a, b) => new Date(b.date) - new Date(a.date))
  }

  const tabs = [
    { id: 'oversikt', label: '📊 Oversikt' },
    { id: 'historikk', label: '📜 Historikk' },
    { id: 'prosjekter', label: `🏗️ Prosjekter (${prosjekter.length})` },
    { id: 'okonomi', label: `💰 Økonomi (${tilbud.length + fakturaer.length})` },
    { id: 'notater', label: `📝 Notater (${notater.length})` },
  ]

  const card = { background:'white', borderRadius:'16px', border:'1px solid #f1f5f9', padding:'20px 24px', boxShadow:'0 1px 4px rgba(0,0,0,0.04)' }

  return (
    <div style={{ fontFamily:'system-ui,sans-serif' }}>
      {/* Header */}
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding:'20px 32px' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', cursor:'pointer', color:'#64748b', fontSize:'13px', marginBottom:'12px', display:'flex', alignItems:'center', gap:'6px', padding:0 }}>← Tilbake til kunder</button>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', flexWrap:'wrap', gap:'12px' }}>
          <div style={{ display:'flex', alignItems:'center', gap:'14px' }}>
            <div style={{ width:'52px', height:'52px', borderRadius:'14px', background:type.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'24px' }}>{type.emoji}</div>
            <div>
              <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
                <h1 style={{ margin:0, fontSize:'20px', fontWeight:'800', color:'#0f172a' }}>{kunde.name}</h1>
                <span style={{ background:type.bg, color:type.color, borderRadius:'999px', fontSize:'12px', fontWeight:'700', padding:'2px 10px' }}>{type.label}</span>
              </div>
              <div style={{ fontSize:'13px', color:'#64748b', marginTop:'3px' }}>
                {kunde.orgnr && <span>Org.nr: {kunde.orgnr}  </span>}
                {kunde.city && <span>📍 {kunde.city}</span>}
              </div>
            </div>
          </div>
          <button onClick={() => setEditing(true)}
            style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding:'9px 20px', cursor:'pointer', fontSize:'14px', fontWeight:'600' }}>
            ✏️ Rediger
          </button>
        </div>

        {/* Tabs */}
        <div style={{ display:'flex', gap:'0', marginTop:'16px', borderBottom:'1px solid #f1f5f9', marginLeft:'-32px', marginRight:'-32px', paddingLeft:'32px' }}>
          {tabs.map(t => (
            <button key={t.id} onClick={() => setActiveTab(t.id)}
              style={{ padding:'10px 18px', border:'none', cursor:'pointer', fontSize:'13px', fontWeight: activeTab === t.id ? '700' : '400', background:'transparent', color: activeTab === t.id ? '#059669' : '#64748b', borderBottom: activeTab === t.id ? '2px solid #059669' : '2px solid transparent', fontFamily:'system-ui,sans-serif' }}>
              {t.label}
            </button>
          ))}
        </div>
      </div>

      <div style={{ padding:'24px 32px', display:'grid', gridTemplateColumns:'1fr 340px', gap:'20px' }}>
        {/* Venstre kolonne */}
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>

          {/* ═══ OVERSIKT TAB ═══ */}
          {activeTab === 'oversikt' && (
            <>
              {/* Nøkkeltall */}
              <div style={{ display:'grid', gridTemplateColumns:'repeat(4, 1fr)', gap:'10px' }}>
                {[
                  { label: 'Totalt fakturert', value: Math.round(totalFakturert).toLocaleString('nb-NO') + ' kr', color: '#059669', bg: '#ecfdf5' },
                  { label: 'Utestående', value: Math.round(utestaende).toLocaleString('nb-NO') + ' kr', color: utestaende > 0 ? '#d97706' : '#059669', bg: utestaende > 0 ? '#fffbeb' : '#ecfdf5' },
                  { label: 'Aktive prosjekter', value: prosjekter.filter(p => p.status === 'aktiv').length, color: '#2563eb', bg: '#eff6ff' },
                  { label: 'Åpne avvik', value: avvik.filter(a => a.status !== 'Lukket').length, color: avvik.filter(a => a.status !== 'Lukket').length > 0 ? '#dc2626' : '#059669', bg: avvik.filter(a => a.status !== 'Lukket').length > 0 ? '#fef2f2' : '#ecfdf5' },
                ].map((s, i) => (
                  <div key={i} style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'16px', textAlign:'center' }}>
                    <div style={{ fontSize:'22px', fontWeight:'800', color:s.color }}>{s.value}</div>
                    <div style={{ fontSize:'11px', color:'#64748b', fontWeight:'500', marginTop:'4px' }}>{s.label}</div>
                  </div>
                ))}
              </div>

              {/* Kontaktinfo */}
              <div style={card}>
                <h3 style={{ margin:'0 0 16px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📋 Kontaktinformasjon</h3>
                <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'10px' }}>
                  {[
                    ['E-post', kunde.email, `mailto:${kunde.email}`],
                    ['Telefon', kunde.phone, `tel:${kunde.phone}`],
                    ['Adresse', kunde.address, null],
                    ['Postnummer / By', [kunde.postal_code, kunde.city].filter(Boolean).join(' '), null],
                    ['Org.nummer', kunde.orgnr, null],
                    ['Faktura e-post', kunde.invoice_email, `mailto:${kunde.invoice_email}`],
                  ].filter(r => r[1]).map(([label, value, href]) => (
                    <div key={label} style={{ background:'#f8fafc', borderRadius:'10px', padding:'10px 14px' }}>
                      <div style={{ fontSize:'11px', color:'#94a3b8', fontWeight:'600', textTransform:'uppercase', marginBottom:'3px' }}>{label}</div>
                      {href
                        ? <a href={href} style={{ fontSize:'14px', fontWeight:'600', color:'#059669', textDecoration:'none' }}>{value}</a>
                        : <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>{value}</div>
                      }
                    </div>
                  ))}
                </div>
                {kunde.notes && (
                  <div style={{ marginTop:'12px', background:'#fffbeb', borderRadius:'10px', padding:'12px 14px', border:'1px solid #fde68a' }}>
                    <div style={{ fontSize:'11px', color:'#92400e', fontWeight:'600', marginBottom:'4px' }}>MERKNAD</div>
                    <p style={{ margin:0, fontSize:'14px', color:'#475569', lineHeight:1.6 }}>{kunde.notes}</p>
                  </div>
                )}
              </div>

              {/* Siste aktivitet (mini-tidslinje) */}
              <div style={card}>
                <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>🕐 Siste aktivitet</h3>
                {buildTimeline().slice(0, 6).map((ev, i) => (
                  <div key={i} style={{ display:'flex', gap:'10px', padding:'8px 0', borderBottom: i < 5 ? '1px solid #f8fafc' : 'none' }}>
                    <span style={{ fontSize:'15px', flexShrink:0, marginTop:'1px' }}>{ev.icon}</span>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{ev.title}</div>
                      <div style={{ fontSize:'11px', color:'#94a3b8' }}>{ev.sub} · {new Date(ev.date).toLocaleDateString('nb-NO')}</div>
                    </div>
                  </div>
                ))}
                {buildTimeline().length > 6 && (
                  <button onClick={() => setActiveTab('historikk')} style={{ background:'none', border:'none', cursor:'pointer', color:'#2563eb', fontSize:'12px', fontWeight:'600', padding:'8px 0 0', display:'block' }}>
                    Vis all historikk ({buildTimeline().length} hendelser) →
                  </button>
                )}
                {buildTimeline().length === 0 && <p style={{ margin:0, color:'#94a3b8', fontSize:'13px' }}>Ingen aktivitet registrert ennå.</p>}
              </div>
            </>
          )}

          {/* ═══ HISTORIKK TAB ═══ */}
          {activeTab === 'historikk' && (
            <div style={card}>
              <h3 style={{ margin:'0 0 16px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📜 Komplett kundehistorikk ({buildTimeline().length} hendelser)</h3>
              {buildTimeline().length === 0 ? (
                <p style={{ margin:0, color:'#94a3b8', fontSize:'13px' }}>Ingen historikk ennå.</p>
              ) : (
                <div style={{ display:'flex', flexDirection:'column' }}>
                  {buildTimeline().map((ev, i) => (
                    <div key={i} style={{ display:'flex', gap:'12px', paddingBottom:'14px', paddingTop: i > 0 ? '14px' : '0', borderTop: i > 0 ? '1px solid #f8fafc' : 'none' }}>
                      <div style={{ display:'flex', flexDirection:'column', alignItems:'center', flexShrink:0 }}>
                        <div style={{ width:'32px', height:'32px', borderRadius:'50%', background: ev.color + '15', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'14px' }}>{ev.icon}</div>
                        {i < buildTimeline().length - 1 && <div style={{ width:'2px', flex:1, background:'#f1f5f9', marginTop:'4px' }} />}
                      </div>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'2px' }}>
                          <span style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', flex:1 }}>{ev.title}</span>
                          <span style={{ fontSize:'11px', color:ev.color, fontWeight:'600', background: ev.color + '15', padding:'1px 8px', borderRadius:'6px', flexShrink:0 }}>{ev.type}</span>
                        </div>
                        <div style={{ fontSize:'12px', color:'#64748b' }}>{ev.sub}</div>
                        <div style={{ fontSize:'11px', color:'#cbd5e1', marginTop:'2px' }}>{new Date(ev.date).toLocaleDateString('nb-NO', { day:'numeric', month:'short', year:'numeric' })}</div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* ═══ PROSJEKTER TAB ═══ */}
          {activeTab === 'prosjekter' && (
            <>
              <div style={card}>
                <h3 style={{ margin:'0 0 16px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>🏗️ Prosjekter ({prosjekter.length})</h3>
                {prosjekter.length === 0 ? (
                  <p style={{ margin:0, color:'#94a3b8', fontSize:'13px' }}>Ingen prosjekter koblet til denne kunden.</p>
                ) : (
                  <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                    {prosjekter.map(p => (
                      <div key={p.id} style={{ display:'flex', alignItems:'center', gap:'10px', background:'#f8fafc', borderRadius:'10px', padding:'12px 14px' }}>
                        <span style={{ fontSize:'16px' }}>🏗️</span>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>{p.name}</div>
                          {avvik.filter(a => a.project_id === p.id).length > 0 && (
                            <div style={{ fontSize:'11px', color:'#ea580c', marginTop:'2px' }}>⚠️ {avvik.filter(a => a.project_id === p.id && a.status !== 'Lukket').length} åpne avvik</div>
                          )}
                        </div>
                        <span style={{ fontSize:'12px', color:'#64748b', background:'white', borderRadius:'6px', padding:'2px 8px', border:'1px solid #e2e8f0' }}>{p.status || 'Aktiv'}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
              {avvik.length > 0 && (
                <div style={card}>
                  <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>⚠️ Avvik ({avvik.length})</h3>
                  <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
                    {avvik.map(a => {
                      const proj = prosjekter.find(p => p.id === a.project_id)
                      const sevCol = { Kritisk:'#dc2626', Hoy:'#ea580c', Medium:'#d97706', Lav:'#16a34a' }[a.severity] || '#d97706'
                      return (
                        <div key={a.id} style={{ display:'flex', alignItems:'center', gap:'10px', background:'#f8fafc', borderRadius:'10px', padding:'10px 14px' }}>
                          <span style={{ width:'8px', height:'8px', borderRadius:'50%', background:sevCol, flexShrink:0 }} />
                          <div style={{ flex:1, minWidth:0 }}>
                            <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>{a.title}</div>
                            <div style={{ fontSize:'11px', color:'#94a3b8' }}>{proj?.name} · {new Date(a.created_at).toLocaleDateString('nb-NO')}</div>
                          </div>
                          <span style={{ fontSize:'11px', fontWeight:'600', color: a.status === 'Lukket' ? '#059669' : '#d97706', background: a.status === 'Lukket' ? '#ecfdf5' : '#fffbeb', padding:'2px 8px', borderRadius:'6px' }}>{a.status}</span>
                        </div>
                      )
                    })}
                  </div>
                </div>
              )}
            </>
          )}

          {/* ═══ ØKONOMI TAB ═══ */}
          {activeTab === 'okonomi' && (
            <>
              {/* Økonomi-oppsummering */}
              <div style={{ display:'grid', gridTemplateColumns:'repeat(3, 1fr)', gap:'10px' }}>
                {[
                  { label: 'Totalt fakturert', value: Math.round(totalFakturert).toLocaleString('nb-NO') + ' kr', color: '#059669', bg: '#ecfdf5' },
                  { label: 'Utestående', value: Math.round(utestaende).toLocaleString('nb-NO') + ' kr', color: utestaende > 0 ? '#d97706' : '#059669', bg: utestaende > 0 ? '#fffbeb' : '#ecfdf5' },
                  { label: 'Forfalt', value: forfalt.length + ' faktura' + (forfalt.length !== 1 ? 'er' : ''), color: forfalt.length > 0 ? '#dc2626' : '#059669', bg: forfalt.length > 0 ? '#fef2f2' : '#ecfdf5' },
                ].map((s, i) => (
                  <div key={i} style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'16px', textAlign:'center' }}>
                    <div style={{ fontSize:'20px', fontWeight:'800', color:s.color }}>{s.value}</div>
                    <div style={{ fontSize:'11px', color:'#64748b', fontWeight:'500', marginTop:'4px' }}>{s.label}</div>
                  </div>
                ))}
              </div>

              {/* Tilbud */}
              <div style={card}>
                <h3 style={{ margin:'0 0 16px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📋 Tilbud ({tilbud.length})</h3>
                {tilbud.length === 0 ? (
                  <p style={{ margin:0, color:'#94a3b8', fontSize:'13px' }}>Ingen tilbud sendt til denne kunden.</p>
                ) : (
                  <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                    {tilbud.map(t => {
                      const statusCfg = { Utkast:{bg:'#f8fafc',color:'#64748b'}, Sendt:{bg:'#eff6ff',color:'#2563eb'}, Akseptert:{bg:'#f0fdf4',color:'#059669'}, Avslått:{bg:'#fef2f2',color:'#dc2626'} }[t.status] || {bg:'#f8fafc',color:'#64748b'}
                      return (
                        <div key={t.id} style={{ display:'flex', alignItems:'center', gap:'12px', background:'#f8fafc', borderRadius:'10px', padding:'10px 14px' }}>
                          <span style={{ fontSize:'16px' }}>📋</span>
                          <div style={{ flex:1, minWidth:0 }}>
                            <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{t.title}</div>
                            <div style={{ fontSize:'12px', color:'#94a3b8' }}>{new Date(t.created_at).toLocaleDateString('nb-NO')}</div>
                          </div>
                          {t.total_amount && <span style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a' }}>{Math.round(t.total_amount).toLocaleString('nb-NO')} kr</span>}
                          <span style={{ background:statusCfg.bg, color:statusCfg.color, borderRadius:'999px', fontSize:'11px', fontWeight:'700', padding:'2px 8px', flexShrink:0 }}>{t.status}</span>
                        </div>
                      )
                    })}
                  </div>
                )}
              </div>

              {/* Fakturaer */}
              <div style={card}>
                <h3 style={{ margin:'0 0 16px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>🧾 Fakturaer ({fakturaer.length})</h3>
                {fakturaer.length === 0 ? (
                  <p style={{ margin:0, color:'#94a3b8', fontSize:'13px' }}>Ingen fakturaer for denne kunden.</p>
                ) : (
                  <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                    {fakturaer.map(f => {
                      const isOverdue = f.status !== 'Betalt' && f.due_date && f.due_date < new Date().toISOString().split('T')[0]
                      const statusColor = f.status === 'Betalt' ? '#059669' : isOverdue ? '#dc2626' : '#d97706'
                      const statusBg = f.status === 'Betalt' ? '#f0fdf4' : isOverdue ? '#fef2f2' : '#fffbeb'
                      return (
                        <div key={f.id} style={{ display:'flex', alignItems:'center', gap:'12px', background:'#f8fafc', borderRadius:'10px', padding:'10px 14px' }}>
                          <span style={{ fontSize:'16px' }}>🧾</span>
                          <div style={{ flex:1, minWidth:0 }}>
                            <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{f.title}</div>
                            <div style={{ fontSize:'12px', color:'#94a3b8' }}>{f.due_date ? `Forfall: ${new Date(f.due_date).toLocaleDateString('nb-NO')}` : new Date(f.created_at).toLocaleDateString('nb-NO')}</div>
                          </div>
                          {f.total_amount && <span style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a' }}>{Math.round(f.total_amount).toLocaleString('nb-NO')} kr</span>}
                          <span style={{ background:statusBg, color:statusColor, borderRadius:'999px', fontSize:'11px', fontWeight:'700', padding:'2px 8px', flexShrink:0 }}>{isOverdue ? 'Forfalt' : f.status}</span>
                        </div>
                      )
                    })}
                  </div>
                )}
              </div>
            </>
          )}

          {/* ═══ NOTATER TAB ═══ */}
          {activeTab === 'notater' && (
            <div style={card}>
              <h3 style={{ margin:'0 0 16px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📝 Notater og korrespondanse</h3>
              <div style={{ display:'flex', gap:'8px', marginBottom:'14px' }}>
                <textarea value={nyttNotat} onChange={e => setNyttNotat(e.target.value)}
                  placeholder="Skriv et notat om kunden, et møte, en telefonsamtale..."
                  rows={3} style={{ ...kundeInp, flex:1, resize:'none', fontSize:'13px' }} />
                <button onClick={lagreNotat} disabled={!nyttNotat.trim()}
                  style={{ background: nyttNotat.trim() ? '#059669' : '#e2e8f0', color: nyttNotat.trim() ? 'white' : '#94a3b8',
                    border:'none', borderRadius:'10px', padding:'0 16px', cursor: nyttNotat.trim() ? 'pointer' : 'not-allowed', fontSize:'13px', fontWeight:'600', whiteSpace:'nowrap', alignSelf:'flex-end', height:'40px' }}>
                  Lagre
                </button>
              </div>
              {notater.length === 0 ? (
                <p style={{ margin:0, color:'#94a3b8', fontSize:'13px' }}>Ingen notater ennå.</p>
              ) : (
                <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                  {notater.map(n => (
                    <div key={n.id} style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px 14px', display:'flex', gap:'10px' }}>
                      <div style={{ flex:1 }}>
                        <p style={{ margin:'0 0 4px', fontSize:'14px', color:'#374151', lineHeight:1.5, whiteSpace:'pre-wrap' }}>{n.content}</p>
                        <span style={{ fontSize:'11px', color:'#94a3b8' }}>{new Date(n.created_at).toLocaleDateString('nb-NO', {day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit'})}</span>
                      </div>
                      <button onClick={() => slettNotat(n.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'14px', padding:'0', alignSelf:'flex-start' }}>🗑️</button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Høyre kolonne — kontaktpersoner (alltid synlig) */}
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          <div style={card}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'16px' }}>
              <h3 style={{ margin:0, fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>👥 Kontaktpersoner</h3>
              <button onClick={() => setShowNyKontakt(true)}
                style={{ background:'#f0fdf4', color:'#059669', border:'1px solid #bbf7d0', borderRadius:'8px', padding:'6px 12px', cursor:'pointer', fontSize:'12px', fontWeight:'600' }}>
                + Legg til
              </button>
            </div>
            {kontakter.length === 0 ? (
              <p style={{ margin:0, color:'#94a3b8', fontSize:'13px' }}>Ingen kontaktpersoner registrert.</p>
            ) : (
              <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
                {kontakter.map(k => (
                  <div key={k.id} style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px 14px' }}>
                    <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between' }}>
                      <div>
                        <div style={{ fontWeight:'700', fontSize:'14px', color:'#0f172a', marginBottom:'4px' }}>{k.name}</div>
                        {k.title && <div style={{ fontSize:'12px', color:'#64748b', marginBottom:'4px' }}>{k.title}</div>}
                        {k.email && <a href={`mailto:${k.email}`} style={{ display:'block', fontSize:'12px', color:'#059669', textDecoration:'none', marginBottom:'2px' }}>✉️ {k.email}</a>}
                        {k.phone && <a href={`tel:${k.phone}`} style={{ display:'block', fontSize:'12px', color:'#059669', textDecoration:'none' }}>📞 {k.phone}</a>}
                      </div>
                      <button onClick={() => slettKontakt(k.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'13px', padding:'0' }}>🗑️</button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Hurtigstatistikk */}
          <div style={card}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📈 Oppsummering</h3>
            <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
              {[
                { label: 'Prosjekter', value: prosjekter.length, icon: '🏗️' },
                { label: 'Tilbud sendt', value: tilbud.length, icon: '📋' },
                { label: 'Aksepterte tilbud', value: aksepterteTilbud.length, icon: '✅' },
                { label: 'Fakturaer', value: fakturaer.length, icon: '🧾' },
                { label: 'Ordrer', value: ordrer.length, icon: '📦' },
                { label: 'Avvik', value: avvik.length, icon: '⚠️' },
                { label: 'Notater', value: notater.length, icon: '📝' },
              ].filter(s => s.value > 0).map((s, i) => (
                <div key={i} style={{ display:'flex', justifyContent:'space-between', alignItems:'center', fontSize:'13px' }}>
                  <span style={{ color:'#64748b' }}>{s.icon} {s.label}</span>
                  <span style={{ fontWeight:'700', color:'#0f172a' }}>{s.value}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {editing && <KundeModal user={user} initial={kunde} onClose={() => setEditing(false)} onSaved={() => { setEditing(false); onRefresh() }} />}
      {showNyKontakt && <KontaktpersonModal customerId={kunde.id} onClose={() => setShowNyKontakt(false)} onSaved={() => { setShowNyKontakt(false); loadDetails() }} />}
    </div>
  )
}

function KundeModal({ user, initial, onClose, onSaved, existingKunder = [] }) {
  const isEdit = !!initial
  const [form, setForm] = useState({
    name: initial?.name || '',
    type: initial?.type || 'bedrift',
    orgnr: initial?.orgnr || '',
    email: initial?.email || '',
    phone: initial?.phone || '',
    address: initial?.address || '',
    postal_code: initial?.postal_code || '',
    city: initial?.city || '',
    invoice_email: initial?.invoice_email || '',
    notes: initial?.notes || '',
  })
  const [saving, setSaving] = useState(false)
  const [dupWarning, setDupWarning] = useState(null)
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }))

  // Live duplikatsjekk
  const checkDuplicate = (field, value) => {
    set(field, value)
    if (!value?.trim()) { setDupWarning(null); return }
    const trimmed = value.trim().toLowerCase()
    let dup = null
    if (field === 'name') {
      dup = existingKunder.find(k => k.name?.toLowerCase() === trimmed && k.id !== initial?.id)
      if (dup) setDupWarning(`Kunde med navn "${dup.name}" finnes allerede`)
      else setDupWarning(null)
    } else if (field === 'orgnr' && value.trim()) {
      dup = existingKunder.find(k => k.orgnr === value.trim() && k.id !== initial?.id)
      if (dup) setDupWarning(`Org.nr ${value.trim()} tilhorer allerede "${dup.name}"`)
      else setDupWarning(null)
    }
  }

  const handleSave = async (e) => {
    e.preventDefault()
    if (!form.name.trim()) return alert('Navn er påkrevd')
    setSaving(true)
    try {
      if (isEdit) {
        const { error } = await supabase.from('customers').update({ ...form, updated_at: new Date().toISOString() }).eq('id', initial.id)
        if (error) throw error
      } else {
        const { error } = await supabase.from('customers').insert({ ...form, created_by: user?.id })
        if (error) throw error
      }
      onSaved()
    } catch(e) { alert('Feil: ' + e.message) }
    finally { setSaving(false) }
  }

  const lbl = (t) => <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'5px' }}>{t}</label>

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px', fontFamily:'system-ui,sans-serif' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'600px', maxHeight:'90vh', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', overflow:'hidden' }}>
        <div style={{ padding:'18px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>🏢 {isEdit ? 'Rediger kunde' : 'Ny kunde'}</h2>
          <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
            <button type="button" onClick={onClose} style={{ padding:'8px 16px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleSave} disabled={saving} style={{ padding:'8px 20px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize:'14px', fontWeight:'700' }}>{saving?'Lagrer...':isEdit?'Lagre':'Opprett kunde'}</button>
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8', marginLeft:'4px' }}>×</button>
          </div>
        </div>
        <form onSubmit={handleSave} style={{ padding:'20px 24px', display:'flex', flexDirection:'column', gap:'14px', overflowY:'auto' }}>
          {/* Kundetype */}
          <div>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>Type kunde</label>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:'8px' }}>
              {Object.entries(KUNDE_TYPE).map(([key, cfg]) => (
                <button key={key} type="button" onClick={() => set('type', key)}
                  style={{ padding:'9px 8px', borderRadius:'10px', border:`2px solid ${form.type === key ? cfg.color : '#e2e8f0'}`,
                    background: form.type === key ? cfg.bg : 'white', cursor:'pointer', fontSize:'12px', fontWeight:'700',
                    color: form.type === key ? cfg.color : '#64748b', textAlign:'center' }}>
                  {cfg.emoji} {cfg.label}
                </button>
              ))}
            </div>
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'12px' }}>
            <div style={{ gridColumn:'1/-1' }}>
              {lbl('Navn *')}<input value={form.name} onChange={e => checkDuplicate('name', e.target.value)} required placeholder="Bedriftsnavn eller fullt navn" style={{ ...kundeInp, borderColor: dupWarning && form.name ? '#f87171' : '#e2e8f0' }} />
              {dupWarning && <p style={{ margin:'4px 0 0', fontSize:'12px', color:'#dc2626' }}>{dupWarning}</p>}
            </div>
            <div>{lbl('Organisasjonsnummer')}<input value={form.orgnr} onChange={e => checkDuplicate('orgnr', e.target.value)} placeholder="9 siffer" style={kundeInp} /></div>
            <div>{lbl('E-post')}<input type="email" value={form.email} onChange={e => set('email', e.target.value)} placeholder="kontakt@bedrift.no" style={kundeInp} /></div>
            <div>{lbl('Telefon')}<input value={form.phone} onChange={e => set('phone', e.target.value)} placeholder="+47 000 00 000" style={kundeInp} /></div>
            <div>{lbl('Faktura e-post')}<input type="email" value={form.invoice_email} onChange={e => set('invoice_email', e.target.value)} placeholder="faktura@bedrift.no" style={kundeInp} /></div>
            <div style={{ gridColumn:'1/-1' }}>{lbl('Adresse')}<input value={form.address} onChange={e => set('address', e.target.value)} placeholder="Gateadresse" style={kundeInp} /></div>
            <div>{lbl('Postnummer')}<input value={form.postal_code} onChange={e => set('postal_code', e.target.value)} placeholder="0000" style={kundeInp} /></div>
            <div>{lbl('By / Sted')}<input value={form.city} onChange={e => set('city', e.target.value)} placeholder="Oslo" style={kundeInp} /></div>
            <div style={{ gridColumn:'1/-1' }}>{lbl('Merknad / notat')}<textarea value={form.notes} onChange={e => set('notes', e.target.value)} rows={2} placeholder="Interne merknader om kunden..." style={{ ...kundeInp, resize:'none' }} /></div>
          </div>

        </form>
      </div>
    </div>
  )
}

function KontaktpersonModal({ customerId, onClose, onSaved }) {
  const [form, setForm] = useState({ name:'', title:'', email:'', phone:'' })
  const [saving, setSaving] = useState(false)
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }))

  const handleSave = async (e) => {
    e.preventDefault()
    if (!form.name.trim()) return alert('Navn er påkrevd')
    setSaving(true)
    try {
      const { error } = await supabase.from('customer_contacts').insert({ ...form, customer_id: customerId })
      if (error) throw error
      onSaved()
    } catch(e) { alert('Feil: ' + e.message) }
    finally { setSaving(false) }
  }

  const lbl = (t) => <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'5px' }}>{t}</label>

  return (
    <div style={{ position:'fixed', inset:0, zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px', fontFamily:'system-ui,sans-serif' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'440px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', overflow:'hidden' }}>
        <div style={{ padding:'18px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <h2 style={{ margin:0, fontSize:'17px', fontWeight:'700', color:'#0f172a' }}>👤 Ny kontaktperson</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <form onSubmit={handleSave} style={{ padding:'20px 24px', display:'flex', flexDirection:'column', gap:'12px' }}>
          <div>{lbl('Navn *')}<input value={form.name} onChange={e => set('name', e.target.value)} required placeholder="Fullt navn" style={kundeInp} /></div>
          <div>{lbl('Stilling / Rolle')}<input value={form.title} onChange={e => set('title', e.target.value)} placeholder="F.eks. Prosjektleder" style={kundeInp} /></div>
          <div>{lbl('E-post')}<input type="email" value={form.email} onChange={e => set('email', e.target.value)} placeholder="navn@bedrift.no" style={kundeInp} /></div>
          <div>{lbl('Telefon')}<input value={form.phone} onChange={e => set('phone', e.target.value)} placeholder="+47 000 00 000" style={kundeInp} /></div>

        </form>
      </div>
    </div>
  )
}

// ─── END KUNDER MODULE ────────────────────────────────────────────────────────

// ─── CRM MODULE ───────────────────────────────────────────────────────────────

const CRM_STATUS = {
  lead:          { label:'Lead',          emoji:'🎯', color:'#64748b', bg:'#f8fafc', border:'#e2e8f0' },
  kontaktet:     { label:'Kontaktet',     emoji:'📞', color:'#2563eb', bg:'#eff6ff', border:'#bfdbfe' },
  tilbud_sendt:  { label:'Tilbud sendt',  emoji:'📋', color:'#d97706', bg:'#fffbeb', border:'#fde68a' },
  vunnet:        { label:'Vunnet',        emoji:'🏆', color:'#16a34a', bg:'#f0fdf4', border:'#bbf7d0' },
  tapt:          { label:'Tapt',          emoji:'❌', color:'#dc2626', bg:'#fef2f2', border:'#fecaca' },
  inaktiv:       { label:'Inaktiv',       emoji:'💤', color:'#94a3b8', bg:'#f8fafc', border:'#e2e8f0' },
}

const CRM_TYPE = {
  firma:   { label:'Firma',   emoji:'🏢' },
  privat:  { label:'Privat',  emoji:'👤' },
  lead:    { label:'Lead',    emoji:'🎯' },
}

const ACTIVITY_TYPES = {
  call:    { label:'Samtale',  emoji:'📞', color:'#2563eb' },
  meeting: { label:'Møte',     emoji:'🤝', color:'#7c3aed' },
  email:   { label:'E-post',   emoji:'📧', color:'#0891b2' },
  note:    { label:'Notat',    emoji:'📝', color:'#64748b' },
  task:    { label:'Oppgave',  emoji:'✅', color:'#d97706' },
}

const INDUSTRIES = ['Bygg & Anlegg','Eiendom','Industri','Handel','Transport','Offentlig','Helse','IT','Finans','Annet']

const crmInp = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', fontFamily:'system-ui,sans-serif' }
const crmCard = { background:'white', borderRadius:'16px', border:'1px solid #f1f5f9', padding:'20px 24px', boxShadow:'0 1px 4px rgba(0,0,0,0.04)' }

function CrmStatusBadge({ status }) {
  const cfg = CRM_STATUS[status]||CRM_STATUS.lead
  return <span style={{ background:cfg.bg, color:cfg.color, border:`1px solid ${cfg.border}`, padding:'3px 10px', borderRadius:'999px', fontSize:'12px', fontWeight:'600' }}>{cfg.emoji} {cfg.label}</span>
}

function fmtVal(n) { return n ? (Math.round(parseFloat(n)||0)).toLocaleString('nb-NO')+' kr' : '—' }

// ── MAIN PAGE ─────────────────────────────────────────────────────────────────
function CRMPage() {
  const { user } = useAuth()
  const [customers, setCustomers] = useState([])
  const [contacts, setContacts] = useState([])
  const [activities, setActivities] = useState([])
  const [projects, setProjects] = useState([])
  const [quotes, setQuotes] = useState([])
  const [invoices, setInvoices] = useState([])
  const [loading, setLoading] = useState(true)
  const [view, setView] = useState('liste') // 'liste'|'pipeline'
  const [filterStatus, setFilterStatus] = useState('alle')
  const [filterType, setFilterType] = useState('alle')
  const [filterIndustry, setFilterIndustry] = useState('alle')
  const [search, setSearch] = useState('')
  const [selected, setSelected] = useState(null)
  const [showNew, setShowNew] = useState(false)

  const load = async () => {
    try {
      const [c, ct, act, proj, q, inv] = await Promise.all([
        supabase.from('crm_customers').select('*').order('updated_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('crm_contacts').select('*').then(r=>r.data||[]),
        supabase.from('crm_activities').select('*').order('created_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('projects').select('id,name,status').order('name').then(r=>r.data||[]),
        supabase.from('quotes').select('*').order('created_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('invoices').select('*').order('created_at',{ascending:false}).then(r=>r.data||[]),
      ])
      setCustomers(c); setContacts(ct); setActivities(act)
      setProjects(proj); setQuotes(q); setInvoices(inv)
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(()=>{ load() },[])

  // Check overdue tasks and create notifications
  useEffect(()=>{
    if (!user||activities.length===0) return
    const today = new Date().toISOString().split('T')[0]
    activities.filter(a=>a.type==='task'&&!a.completed&&a.due_date&&a.due_date<today).forEach(async a=>{
      const cust = customers.find(c=>c.id===a.customer_id)
      const { data } = await supabase.from('notifications').select('id').eq('user_id',user.id).ilike('title',`%${a.title}%`).gte('created_at',today+'T00:00:00').limit(1)
      if (!data||data.length===0) {
        await supabase.from('notifications').insert({ user_id:user.id, title:`Forfalt oppgave: ${a.title}`, message:cust?`Kunde: ${cust.name}`:'', type:'warning', link_page:'crm' })
      }
    })
  },[activities])

  const filtered = customers.filter(c=>{
    if (filterStatus!=='alle'&&c.status!==filterStatus) return false
    if (filterType!=='alle'&&c.type!==filterType) return false
    if (filterIndustry!=='alle'&&c.industry!==filterIndustry) return false
    if (search&&![c.name,c.email,c.phone,c.city,c.orgnr].some(v=>v?.toLowerCase().includes(search.toLowerCase()))) return false
    return true
  })

  const stats = {
    total: customers.length,
    leads: customers.filter(c=>c.status==='lead').length,
    active: customers.filter(c=>['kontaktet','tilbud_sendt'].includes(c.status)).length,
    vunnet: customers.filter(c=>c.status==='vunnet').length,
    pipeline: customers.filter(c=>!['vunnet','tapt','inaktiv'].includes(c.status)).reduce((a,c)=>a+(parseFloat(c.estimated_value)||0),0),
  }

  const overdueTasks = activities.filter(a=>a.type==='task'&&!a.completed&&a.due_date&&a.due_date<new Date().toISOString().split('T')[0])

  const exportCSV = () => {
    const rows = [
      ['Navn','Type','Status','Bransje','E-post','Telefon','By','Org.nr','Estimert verdi','Opprettet'],
      ...filtered.map(c=>[c.name,CRM_TYPE[c.type]?.label||'',CRM_STATUS[c.status]?.label||'',c.industry||'',c.email||'',c.phone||'',c.city||'',c.orgnr||'',c.estimated_value||'',c.created_at?.split('T')[0]||''])
    ]
    const csv = rows.map(r=>r.join(';')).join('\n')
    const blob = new Blob(['\uFEFF'+csv],{type:'text/csv;charset=utf-8'})
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a'); a.href=url; a.download=`crm-kunder-${new Date().toISOString().split('T')[0]}.csv`; a.click()
  }

  if (loading) return <div style={{ display:'flex',alignItems:'center',justifyContent:'center',minHeight:'60vh',fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px',height:'36px',border:'3px solid #e2e8f0',borderTop:'3px solid #059669',borderRadius:'50%',margin:'0 auto 12px',animation:'spin 1s linear infinite' }}/><p style={{ color:'#94a3b8',fontSize:'14px' }}>Laster CRM...</p></div></div>
  if (selected) return <CRMDetaljer customer={selected} contacts={contacts.filter(c=>c.customer_id===selected.id)} activities={activities.filter(a=>a.customer_id===selected.id)} projects={projects} quotes={quotes} invoices={invoices} user={user} onBack={()=>{setSelected(null);load()}} />

  return (
    <div style={{ fontFamily:'system-ui,sans-serif' }}>
      {/* Header */}
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding:'20px 32px' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'16px' }}>
          <div>
            <h1 style={{ fontSize:'22px', fontWeight:'bold', color:'#0f172a', margin:0 }}>🤝 CRM</h1>
            <p style={{ color:'#64748b', marginTop:'4px', fontSize:'14px', marginBottom:0 }}>Kunder, leads og salgspipeline</p>
          </div>
          <div style={{ display:'flex', gap:'8px' }}>
            <button onClick={exportCSV} style={{ padding:'9px 16px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'13px', fontWeight:'600', color:'#475569' }}>📥 Eksporter CSV</button>
            <button onClick={()=>setShowNew(true)} style={{ padding:'10px 20px', background:'#059669', color:'white', border:'none', borderRadius:'12px', cursor:'pointer', fontSize:'14px', fontWeight:'700' }}>+ Ny kunde / lead</button>
          </div>
        </div>

        {/* Stats */}
        <div style={{ display:'grid', gridTemplateColumns:'repeat(5,1fr)', gap:'10px' }}>
          {[
            { label:'Totalt', value:stats.total, emoji:'👥', color:'#0f172a', bg:'#f8fafc' },
            { label:'Leads', value:stats.leads, emoji:'🎯', color:'#64748b', bg:'#f8fafc' },
            { label:'Aktive', value:stats.active, emoji:'📋', color:'#d97706', bg:'#fffbeb' },
            { label:'Vunnet', value:stats.vunnet, emoji:'🏆', color:'#16a34a', bg:'#f0fdf4' },
            { label:'Pipeline', value:fmtVal(stats.pipeline), emoji:'💰', color:'#2563eb', bg:'#eff6ff' },
          ].map(s=>(
            <div key={s.label} style={{ background:s.bg, borderRadius:'12px', padding:'14px 16px', border:'1px solid #f1f5f9' }}>
              <div style={{ display:'flex', alignItems:'center', gap:'6px', marginBottom:'4px' }}>
                <span style={{ fontSize:'16px' }}>{s.emoji}</span>
                <span style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase' }}>{s.label}</span>
              </div>
              <div style={{ fontSize:typeof s.value==='number'?'22px':'16px', fontWeight:'800', color:s.color }}>{s.value}</div>
            </div>
          ))}
        </div>
      </div>

      <div style={{ padding:'20px 32px', display:'flex', flexDirection:'column', gap:'16px' }}>
        {/* Overdue tasks warning */}
        {overdueTasks.length>0&&(
          <div style={{ background:'#fef2f2', borderRadius:'12px', padding:'12px 18px', border:'1px solid #fecaca', display:'flex', alignItems:'center', gap:'10px' }}>
            <span style={{ fontSize:'18px' }}>🚨</span>
            <span style={{ fontSize:'14px', fontWeight:'600', color:'#dc2626' }}>{overdueTasks.length} forfalt oppgave{overdueTasks.length>1?'r':''} krever oppfølging</span>
          </div>
        )}

        {/* Controls */}
        <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'14px 18px', display:'flex', gap:'10px', alignItems:'center', flexWrap:'wrap' }}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 Søk navn, e-post, by, org.nr..." style={{ ...crmInp, maxWidth:'240px', flex:1 }} />
          <select value={filterStatus} onChange={e=>setFilterStatus(e.target.value)} style={{ ...crmInp, maxWidth:'160px' }}>
            <option value="alle">Alle statuser</option>
            {Object.entries(CRM_STATUS).map(([k,v])=><option key={k} value={k}>{v.emoji} {v.label}</option>)}
          </select>
          <select value={filterType} onChange={e=>setFilterType(e.target.value)} style={{ ...crmInp, maxWidth:'140px' }}>
            <option value="alle">Alle typer</option>
            {Object.entries(CRM_TYPE).map(([k,v])=><option key={k} value={k}>{v.emoji} {v.label}</option>)}
          </select>
          <select value={filterIndustry} onChange={e=>setFilterIndustry(e.target.value)} style={{ ...crmInp, maxWidth:'160px' }}>
            <option value="alle">Alle bransjer</option>
            {INDUSTRIES.map(i=><option key={i} value={i}>{i}</option>)}
          </select>
          {(search||filterStatus!=='alle'||filterType!=='alle'||filterIndustry!=='alle')&&<button onClick={()=>{setSearch('');setFilterStatus('alle');setFilterType('alle');setFilterIndustry('alle')}} style={{ background:'#f1f5f9',border:'none',borderRadius:'8px',padding:'9px 14px',fontSize:'13px',cursor:'pointer',color:'#64748b' }}>Nullstill</button>}
          <div style={{ marginLeft:'auto', display:'flex', border:'1px solid #e2e8f0', borderRadius:'10px', overflow:'hidden' }}>
            {[['liste','☰ Liste'],['pipeline','🏊 Pipeline']].map(([v,l])=>(
              <button key={v} onClick={()=>setView(v)} style={{ padding:'8px 14px',border:'none',background:view===v?'#0f172a':'white',color:view===v?'white':'#64748b',fontWeight:view===v?'700':'500',fontSize:'13px',cursor:'pointer' }}>{l}</button>
            ))}
          </div>
          <span style={{ fontSize:'13px', color:'#94a3b8' }}>{filtered.length} kunder</span>
        </div>

        {/* LISTE VIEW */}
        {view==='liste' && (
          filtered.length===0 ? (
            <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'60px 20px', textAlign:'center' }}>
              <div style={{ fontSize:'40px', marginBottom:'12px' }}>🤝</div>
              <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Ingen kunder funnet</h3>
              <p style={{ margin:0, color:'#94a3b8', fontSize:'14px' }}>{customers.length===0?'Legg til din første kunde eller lead.':'Prøv å endre søk eller filter.'}</p>
            </div>
          ) : (
            <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
              {filtered.map(c=>{
                const custContacts=contacts.filter(ct=>ct.customer_id===c.id)
                const custActivities=activities.filter(a=>a.customer_id===c.id)
                const openTasks=custActivities.filter(a=>a.type==='task'&&!a.completed)
                const cfg=CRM_STATUS[c.status]
                const typCfg=CRM_TYPE[c.type]
                return (
                  <div key={c.id} onClick={()=>setSelected(c)}
                    style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'16px 20px', cursor:'pointer', display:'flex', alignItems:'center', gap:'16px', transition:'box-shadow 0.15s' }}
                    onMouseEnter={e=>e.currentTarget.style.boxShadow='0 4px 16px rgba(0,0,0,0.08)'} onMouseLeave={e=>e.currentTarget.style.boxShadow='none'}>
                    <div style={{ width:'44px', height:'44px', borderRadius:'12px', background:cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px', flexShrink:0 }}>{typCfg?.emoji}</div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ display:'flex', alignItems:'center', gap:'8px', flexWrap:'wrap', marginBottom:'4px' }}>
                        <span style={{ fontWeight:'700', color:'#0f172a', fontSize:'15px' }}>{c.name}</span>
                        <CrmStatusBadge status={c.status} />
                        {c.industry&&<span style={{ fontSize:'12px', color:'#94a3b8', background:'#f8fafc', padding:'2px 8px', borderRadius:'999px', border:'1px solid #f1f5f9' }}>{c.industry}</span>}
                        {openTasks.length>0&&<span style={{ background:'#fffbeb', color:'#d97706', fontSize:'11px', fontWeight:'700', padding:'2px 8px', borderRadius:'999px', border:'1px solid #fde68a' }}>⏰ {openTasks.length} oppgave{openTasks.length>1?'r':''}</span>}
                      </div>
                      <div style={{ display:'flex', gap:'12px', flexWrap:'wrap' }}>
                        {c.email&&<span style={{ fontSize:'12px', color:'#64748b' }}>📧 {c.email}</span>}
                        {c.phone&&<span style={{ fontSize:'12px', color:'#64748b' }}>📞 {c.phone}</span>}
                        {c.city&&<span style={{ fontSize:'12px', color:'#64748b' }}>📍 {c.city}</span>}
                        {custContacts.length>0&&<span style={{ fontSize:'12px', color:'#2563eb' }}>👤 {custContacts.length} kontakt{custContacts.length>1?'er':''}</span>}
                        <span style={{ fontSize:'12px', color:'#64748b' }}>📅 {custActivities.length} aktiviteter</span>
                      </div>
                    </div>
                    {c.estimated_value&&<div style={{ textAlign:'right', flexShrink:0 }}>
                      <div style={{ fontWeight:'800', fontSize:'15px', color:'#0f172a' }}>{fmtVal(c.estimated_value)}</div>
                      <div style={{ fontSize:'11px', color:'#94a3b8' }}>est. verdi</div>
                    </div>}
                    <span style={{ color:'#94a3b8', fontSize:'18px' }}>›</span>
                  </div>
                )
              })}
            </div>
          )
        )}

        {/* PIPELINE VIEW */}
        {view==='pipeline' && (
          <div style={{ overflowX:'auto', flex:fullscreen?1:'initial', overflow:fullscreen?'auto':'initial' }}>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(5,280px)', gap:'14px', minWidth:'max-content' }}>
              {['lead','kontaktet','tilbud_sendt','vunnet','tapt'].map(status=>{
                const cfg=CRM_STATUS[status]
                const cols=filtered.filter(c=>c.status===status)
                const colVal=cols.reduce((a,c)=>a+(parseFloat(c.estimated_value)||0),0)
                return (
                  <div key={status}>
                    <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'10px', padding:'0 4px' }}>
                      <div style={{ display:'flex', alignItems:'center', gap:'6px' }}>
                        <span>{cfg.emoji}</span>
                        <span style={{ fontWeight:'700', fontSize:'13px', color:'#0f172a' }}>{cfg.label}</span>
                        <span style={{ background:cfg.bg, color:cfg.color, border:`1px solid ${cfg.border}`, borderRadius:'999px', fontSize:'11px', fontWeight:'700', padding:'1px 7px' }}>{cols.length}</span>
                      </div>
                      {colVal>0&&<span style={{ fontSize:'11px', color:'#94a3b8', fontWeight:'600' }}>{fmtVal(colVal)}</span>}
                    </div>
                    <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                      {cols.map(c=>{
                        const custAct=activities.filter(a=>a.customer_id===c.id)
                        const openTasks=custAct.filter(a=>a.type==='task'&&!a.completed)
                        const lastAct=custAct.sort((a,b)=>new Date(b.created_at)-new Date(a.created_at))[0]
                        return (
                          <div key={c.id} onClick={()=>setSelected(c)}
                            style={{ background:'white', borderRadius:'12px', border:'1px solid #f1f5f9', padding:'14px', cursor:'pointer', boxShadow:'0 1px 4px rgba(0,0,0,0.04)', transition:'box-shadow 0.15s' }}
                            onMouseEnter={e=>e.currentTarget.style.boxShadow='0 4px 12px rgba(0,0,0,0.1)'} onMouseLeave={e=>e.currentTarget.style.boxShadow='0 1px 4px rgba(0,0,0,0.04)'}>
                            <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', marginBottom:'8px' }}>
                              <div>
                                <div style={{ fontWeight:'700', fontSize:'14px', color:'#0f172a', marginBottom:'2px' }}>{c.name}</div>
                                {c.industry&&<div style={{ fontSize:'11px', color:'#94a3b8' }}>{c.industry}</div>}
                              </div>
                              <span style={{ fontSize:'16px' }}>{CRM_TYPE[c.type]?.emoji}</span>
                            </div>
                            {c.estimated_value&&<div style={{ fontWeight:'800', fontSize:'14px', color:'#059669', marginBottom:'6px' }}>{fmtVal(c.estimated_value)}</div>}
                            <div style={{ display:'flex', gap:'6px', flexWrap:'wrap' }}>
                              {c.email&&<span style={{ fontSize:'10px', color:'#64748b' }}>📧</span>}
                              {c.phone&&<span style={{ fontSize:'10px', color:'#64748b' }}>📞</span>}
                              {openTasks.length>0&&<span style={{ background:'#fffbeb', color:'#d97706', fontSize:'10px', fontWeight:'700', padding:'1px 6px', borderRadius:'999px', border:'1px solid #fde68a' }}>⏰ {openTasks.length}</span>}
                            </div>
                            {lastAct&&<div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'6px', borderTop:'1px solid #f8fafc', paddingTop:'6px' }}>{ACTIVITY_TYPES[lastAct.type]?.emoji} {lastAct.title}</div>}
                          </div>
                        )
                      })}
                      {cols.length===0&&<div style={{ background:'#f8fafc', borderRadius:'10px', border:'2px dashed #f1f5f9', padding:'20px', textAlign:'center', fontSize:'12px', color:'#cbd5e1' }}>Ingen her</div>}
                    </div>
                  </div>
                )
              })}
            </div>
          </div>
        )}
      </div>

      {showNew&&<CRMEditorModal user={user} onClose={()=>setShowNew(false)} onSaved={()=>{setShowNew(false);load()}} />}
    </div>
  )
}

function CRMDetaljer({ customer: init, contacts, activities, projects, quotes, invoices, user, onBack }) {
  const confirm = useConfirm()
  const [c, setC] = useState(init)
  const [cts, setCts] = useState(contacts)
  const [acts, setActs] = useState(activities)
  const [docs, setDocs] = useState([])
  const [tab, setTab] = useState('oversikt')
  const [editing, setEditing] = useState(false)
  const [showNewContact, setShowNewContact] = useState(false)
  const [showNewActivity, setShowNewActivity] = useState(false)
  const [showQuotePicker, setShowQuotePicker] = useState(false)
  const fileInputRef = React.useRef(null)
  const cfg = CRM_STATUS[c.status]

  const loadDetails = async () => {
    const [ct, act, doc] = await Promise.all([
      supabase.from('crm_contacts').select('*').eq('customer_id',c.id).then(r=>r.data||[]),
      supabase.from('crm_activities').select('*').eq('customer_id',c.id).order('created_at',{ascending:false}).then(r=>r.data||[]),
      supabase.from('crm_documents').select('*').eq('customer_id',c.id).order('created_at',{ascending:false}).then(r=>r.data||[]),
    ])
    setCts(ct); setActs(act); setDocs(doc)
  }
  useEffect(()=>{ loadDetails() },[c.id])

  const refresh = async () => { const {data}=await supabase.from('crm_customers').select('*').eq('id',c.id).single(); if(data) setC(data) }

  const updateStatus = async (status) => {
    await supabase.from('crm_customers').update({status,updated_at:new Date().toISOString()}).eq('id',c.id)
    setC(v=>({...v,status}))
  }

  const handleDelete = async () => {
    if (!(await confirm({ message: 'Slett denne kunden?', subMessage: 'Kunden og all historikk, aktiviteter og dokumenter slettes permanent.', danger: true }))) return
    await supabase.from('crm_customers').delete().eq('id',c.id)
    onBack()
  }

  const uploadDoc = async (e) => {
    const file=e.target.files?.[0]; if(!file) return
    try {
      const path=`crm/${c.id}/${Date.now()}_${file.name}`
      const {error:upErr}=await supabase.storage.from('plattform-files').upload(path,file)
      if(upErr) throw upErr
      const {data:{publicUrl}}=supabase.storage.from('plattform-files').getPublicUrl(path)
      await supabase.from('crm_documents').insert({ customer_id:c.id, name:file.name, file_url:publicUrl, file_type:file.type, uploaded_by:user?.id })
      loadDetails()
    } catch(e) { alert('Opplasting feilet: '+e.message) }
    e.target.value=''
  }

  const deleteDoc = async (id) => {
    if (!(await confirm({ message: 'Slett dokument?', subMessage: 'Dokumentet slettes permanent.', danger: true }))) return
    await supabase.from('crm_documents').delete().eq('id',id)
    loadDetails()
  }

  const toggleTask = async (act) => {
    await supabase.from('crm_activities').update({completed:!act.completed}).eq('id',act.id)
    loadDetails()
  }

  // Link quote to this customer as activity
  const linkQuote = async (quote) => {
    await supabase.from('crm_activities').insert({
      customer_id:c.id, type:'note',
      title:`Tilbud hentet inn: ${quote.title}`,
      description:`Tilbudsnr: ${quote.quote_number} · Total: ${(quote.chapters||[]).reduce((a,ch)=>{const s=(ch.posts||[]).reduce((x,p)=>(parseFloat(p.qty)||0)*((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0))+x,0);return a+s*(1+(parseFloat(ch.markup)||0)/100)},0).toLocaleString('nb-NO')} kr`,
      date:new Date().toISOString().split('T')[0], created_by:user?.id
    })
    loadDetails(); setShowQuotePicker(false)
  }

  // Linked data
  const linkedQuotes = quotes.filter(q=>q.customer_name&&q.customer_name.toLowerCase()===c.name.toLowerCase())
  const linkedInvoices = invoices.filter(i=>i.customer_name&&i.customer_name.toLowerCase()===c.name.toLowerCase())
  const openTasks = acts.filter(a=>a.type==='task'&&!a.completed)
  const today = new Date().toISOString().split('T')[0]

  const tabs = [
    { id:'oversikt', label:'Oversikt', emoji:'📊' },
    { id:'aktiviteter', label:`Aktiviteter (${acts.length})`, emoji:'📋' },
    { id:'kontakter', label:`Kontakter (${cts.length})`, emoji:'👤' },
    { id:'tilbud', label:`Tilbud (${linkedQuotes.length})`, emoji:'📋' },
    { id:'dokumenter', label:`Dokumenter (${docs.length})`, emoji:'📁' },
  ]

  return (
    <div style={{ fontFamily:'system-ui,sans-serif' }}>
      {/* Header */}
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding:'20px 32px' }}>
        <button onClick={onBack} style={{ background:'none',border:'none',cursor:'pointer',color:'#64748b',fontSize:'13px',marginBottom:'12px',display:'flex',alignItems:'center',gap:'6px',padding:0 }}>← Tilbake til CRM</button>
        <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap:'16px' }}>
          <div style={{ display:'flex', alignItems:'flex-start', gap:'16px' }}>
            <div style={{ width:'56px', height:'56px', borderRadius:'16px', background:cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'26px', flexShrink:0 }}>{CRM_TYPE[c.type]?.emoji}</div>
            <div>
              <div style={{ display:'flex', alignItems:'center', gap:'10px', flexWrap:'wrap', marginBottom:'6px' }}>
                <h1 style={{ margin:0, fontSize:'22px', fontWeight:'800', color:'#0f172a' }}>{c.name}</h1>
                <CrmStatusBadge status={c.status} />
                {c.industry&&<span style={{ fontSize:'13px', color:'#94a3b8', background:'#f8fafc', padding:'3px 10px', borderRadius:'999px', border:'1px solid #f1f5f9' }}>{c.industry}</span>}
              </div>
              <div style={{ display:'flex', gap:'14px', flexWrap:'wrap' }}>
                {c.email&&<span style={{ fontSize:'13px', color:'#64748b' }}>📧 {c.email}</span>}
                {c.phone&&<span style={{ fontSize:'13px', color:'#64748b' }}>📞 {c.phone}</span>}
                {c.city&&<span style={{ fontSize:'13px', color:'#64748b' }}>📍 {c.city}</span>}
                {c.estimated_value&&<span style={{ fontSize:'13px', color:'#059669', fontWeight:'700' }}>💰 {fmtVal(c.estimated_value)}</span>}
              </div>
            </div>
          </div>
          <div style={{ display:'flex', gap:'8px', flexShrink:0 }}>
            <button onClick={()=>setShowQuotePicker(true)} style={{ padding:'9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'13px', fontWeight:'600' }}>📋 Hent tilbud</button>
            <button onClick={()=>setEditing(true)} style={{ padding:'9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'13px' }}>✏️ Rediger</button>
            <button onClick={handleDelete} style={{ padding:'9px 12px', border:'1px solid #fecaca', borderRadius:'10px', background:'white', cursor:'pointer', color:'#dc2626', fontSize:'13px' }}>🗑️</button>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display:'flex', gap:'4px', marginTop:'16px', flexWrap:'wrap' }}>
          {tabs.map(t=>(
            <button key={t.id} onClick={()=>setTab(t.id)}
              style={{ padding:'8px 16px', borderRadius:'10px', border:'none', background:tab===t.id?'#059669':'#f8fafc', color:tab===t.id?'white':'#64748b', fontWeight:tab===t.id?'700':'500', fontSize:'13px', cursor:'pointer' }}>
              {t.emoji} {t.label}
            </button>
          ))}
        </div>
      </div>

      <div style={{ padding:'24px 32px', display:'grid', gridTemplateColumns:'2fr 1fr', gap:'20px' }}>
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>

          {/* OVERSIKT */}
          {tab==='oversikt'&&(
            <>
              <div style={crmCard}>
                <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>ℹ️ Informasjon</h3>
                <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'10px' }}>
                  {[['Navn',c.name],['Type',CRM_TYPE[c.type]?.label],['Org.nr',c.orgnr],['Bransje',c.industry],['E-post',c.email],['Telefon',c.phone],['Nettside',c.website],['Adresse',c.address],['Postnr/By',c.postal&&c.city?`${c.postal} ${c.city}`:c.city||c.postal],['Estimert verdi',c.estimated_value?fmtVal(c.estimated_value):null]].filter(r=>r[1]).map(([k,v])=>(
                    <div key={k} style={{ background:'#f8fafc', borderRadius:'8px', padding:'9px 12px' }}>
                      <div style={{ fontSize:'11px', color:'#94a3b8', textTransform:'uppercase', fontWeight:'600' }}>{k}</div>
                      <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a', marginTop:'2px' }}>{v}</div>
                    </div>
                  ))}
                </div>
                {c.notes&&<div style={{ marginTop:'12px', background:'#f8fafc', borderRadius:'8px', padding:'10px 12px' }}><div style={{ fontSize:'11px', color:'#94a3b8', textTransform:'uppercase', fontWeight:'600', marginBottom:'4px' }}>Notater</div><p style={{ margin:0, fontSize:'13px', color:'#475569', lineHeight:1.6 }}>{c.notes}</p></div>}
              </div>
              {openTasks.length>0&&(
                <div style={{ ...crmCard, background:'#fffbeb', border:'1px solid #fde68a' }}>
                  <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'700', color:'#92400e' }}>⏰ Åpne oppgaver ({openTasks.length})</h3>
                  {openTasks.map(a=>(
                    <div key={a.id} style={{ display:'flex', alignItems:'center', gap:'10px', padding:'8px 0', borderBottom:'1px solid #fde68a' }}>
                      <input type="checkbox" checked={a.completed} onChange={()=>toggleTask(a)} style={{ width:'16px', height:'16px', accentColor:'#059669', cursor:'pointer' }} />
                      <div style={{ flex:1 }}>
                        <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>{a.title}</div>
                        {a.due_date&&<div style={{ fontSize:'11px', color:a.due_date<today?'#dc2626':'#64748b', fontWeight:a.due_date<today?'700':'400' }}>Frist: {a.due_date}{a.due_date<today?' ⚠️ FORFALT':''}</div>}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </>
          )}

          {/* AKTIVITETER */}
          {tab==='aktiviteter'&&(
            <div style={crmCard}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'16px' }}>
                <h3 style={{ margin:0, fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📋 Aktivitetslogg</h3>
                <button onClick={()=>setShowNewActivity(true)} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>+ Legg til</button>
              </div>
              {acts.length===0?<p style={{ color:'#94a3b8', fontSize:'14px', fontStyle:'italic' }}>Ingen aktiviteter ennå</p>:(
                <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
                  {acts.map(a=>{
                    const atCfg=ACTIVITY_TYPES[a.type]
                    const isTask=a.type==='task'
                    return (
                      <div key={a.id} style={{ display:'flex', gap:'12px', padding:'12px 14px', background:'#f8fafc', borderRadius:'12px', border:`1px solid ${isTask&&a.due_date<today&&!a.completed?'#fecaca':'#f1f5f9'}` }}>
                        <div style={{ width:'32px', height:'32px', borderRadius:'8px', background:atCfg?.color+'18', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'16px', flexShrink:0 }}>{atCfg?.emoji}</div>
                        <div style={{ flex:1 }}>
                          <div style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'3px' }}>
                            {isTask&&<input type="checkbox" checked={a.completed} onChange={()=>toggleTask(a)} style={{ width:'14px', height:'14px', accentColor:'#059669', cursor:'pointer' }} />}
                            <span style={{ fontWeight:'700', fontSize:'13px', color:'#0f172a', textDecoration:isTask&&a.completed?'line-through':'none' }}>{a.title}</span>
                            <span style={{ background:atCfg?.color+'18', color:atCfg?.color, fontSize:'10px', fontWeight:'700', padding:'2px 7px', borderRadius:'999px' }}>{atCfg?.label}</span>
                          </div>
                          {a.description&&<p style={{ margin:'0 0 4px', fontSize:'12px', color:'#64748b', lineHeight:1.5 }}>{a.description}</p>}
                          <div style={{ display:'flex', gap:'10px', fontSize:'11px', color:'#94a3b8' }}>
                            <span>📅 {a.date}</span>
                            {a.due_date&&<span style={{ color:a.due_date<today&&!a.completed?'#dc2626':'#64748b', fontWeight:a.due_date<today&&!a.completed?'700':'400' }}>Frist: {a.due_date}</span>}
                          </div>
                        </div>
                      </div>
                    )
                  })}
                </div>
              )}
            </div>
          )}

          {/* KONTAKTER */}
          {tab==='kontakter'&&(
            <div style={crmCard}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'16px' }}>
                <h3 style={{ margin:0, fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>👤 Kontaktpersoner</h3>
                <button onClick={()=>setShowNewContact(true)} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>+ Legg til</button>
              </div>
              {cts.length===0?<p style={{ color:'#94a3b8', fontSize:'14px', fontStyle:'italic' }}>Ingen kontakter ennå</p>:(
                <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
                  {cts.map(ct=>(
                    <div key={ct.id} style={{ display:'flex', alignItems:'center', gap:'12px', background:'#f8fafc', borderRadius:'12px', padding:'12px 16px', border:'1px solid #f1f5f9' }}>
                      <div style={{ width:'40px', height:'40px', borderRadius:'50%', background:'#eff6ff', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'16px', fontWeight:'800', color:'#2563eb', flexShrink:0 }}>{ct.name?.[0]}</div>
                      <div style={{ flex:1 }}>
                        <div style={{ display:'flex', alignItems:'center', gap:'6px', marginBottom:'2px' }}>
                          <span style={{ fontWeight:'700', fontSize:'14px', color:'#0f172a' }}>{ct.name}</span>
                          {ct.is_primary&&<span style={{ background:'#f0fdf4', color:'#16a34a', fontSize:'10px', fontWeight:'700', padding:'1px 7px', borderRadius:'999px', border:'1px solid #bbf7d0' }}>Primær</span>}
                        </div>
                        <div style={{ display:'flex', gap:'10px', flexWrap:'wrap', fontSize:'12px', color:'#64748b' }}>
                          {ct.title&&<span>💼 {ct.title}</span>}
                          {ct.email&&<span>📧 {ct.email}</span>}
                          {ct.phone&&<span>📞 {ct.phone}</span>}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* TILBUD */}
          {tab==='tilbud'&&(
            <div style={crmCard}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'16px' }}>
                <h3 style={{ margin:0, fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📋 Koblede tilbud og fakturaer</h3>
                <button onClick={()=>setShowQuotePicker(true)} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>📋 Hent tilbud</button>
              </div>
              {linkedQuotes.length===0&&linkedInvoices.length===0?<p style={{ color:'#94a3b8', fontSize:'14px', fontStyle:'italic' }}>Ingen koblede tilbud eller fakturaer. Bruk "Hent tilbud" for å koble til eksisterende tilbud.</p>:(
                <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                  {linkedQuotes.map(q=>{
                    const total=(q.chapters||[]).reduce((a,ch)=>{const s=(ch.posts||[]).reduce((x,p)=>(parseFloat(p.qty)||0)*((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0))+x,0);return a+s*(1+(parseFloat(ch.markup)||0)/100)},0)
                    return (
                      <div key={q.id} style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px 16px', border:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                        <div>
                          <div style={{ fontWeight:'700', fontSize:'13px', color:'#0f172a' }}>{q.title}</div>
                          <div style={{ fontSize:'12px', color:'#64748b' }}>{q.quote_number} · Status: {q.status}</div>
                        </div>
                        <div style={{ fontWeight:'800', color:'#059669', fontSize:'14px' }}>{fmtVal(total)}</div>
                      </div>
                    )
                  })}
                  {linkedInvoices.map(inv=>(
                    <div key={inv.id} style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px 16px', border:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                      <div>
                        <div style={{ fontWeight:'700', fontSize:'13px', color:'#0f172a' }}>🧾 {inv.title}</div>
                        <div style={{ fontSize:'12px', color:'#64748b' }}>{inv.invoice_number} · Status: {inv.status}</div>
                      </div>
                      <div style={{ fontWeight:'800', color:'#2563eb', fontSize:'14px' }}>{fmtVal((inv.lines||[]).reduce((a,l)=>(parseFloat(l.qty)||0)*(parseFloat(l.unitPrice)||0)+a,0))}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* DOKUMENTER */}
          {tab==='dokumenter'&&(
            <div style={crmCard}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'16px' }}>
                <h3 style={{ margin:0, fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📁 Dokumenter</h3>
                <button onClick={()=>fileInputRef.current?.click()} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>📎 Last opp</button>
                <input ref={fileInputRef} type="file" style={{ display:'none' }} onChange={uploadDoc} />
              </div>
              {docs.length===0?<p style={{ color:'#94a3b8', fontSize:'14px', fontStyle:'italic' }}>Ingen dokumenter lastet opp</p>:(
                <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                  {docs.map(d=>{
                    const isImage=d.file_type?.startsWith('image/')
                    return (
                      <div key={d.id} style={{ display:'flex', alignItems:'center', gap:'12px', background:'#f8fafc', borderRadius:'10px', padding:'10px 14px', border:'1px solid #f1f5f9' }}>
                        <span style={{ fontSize:'20px' }}>{isImage?'🖼️':'📄'}</span>
                        <div style={{ flex:1, minWidth:0 }}>
                          <a href={d.file_url} target="_blank" rel="noreferrer" style={{ fontWeight:'600', fontSize:'13px', color:'#2563eb', textDecoration:'none', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', display:'block' }}>{d.name}</a>
                          <div style={{ fontSize:'11px', color:'#94a3b8' }}>{new Date(d.created_at).toLocaleDateString('nb-NO')}</div>
                        </div>
                        <button onClick={()=>deleteDoc(d.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'14px' }}>🗑️</button>
                      </div>
                    )
                  })}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          <div style={crmCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>🔄 Status</h3>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {Object.entries(CRM_STATUS).map(([k,v])=>(
                <button key={k} onClick={()=>updateStatus(k)} disabled={c.status===k}
                  style={{ padding:'9px 14px', borderRadius:'10px', border:`1px solid ${c.status===k?v.border:'#e2e8f0'}`, background:c.status===k?v.bg:'white', color:c.status===k?v.color:'#475569', fontWeight:c.status===k?'700':'400', fontSize:'13px', cursor:c.status===k?'default':'pointer', textAlign:'left', width:'100%' }}>
                  {c.status===k?'✓ ':''}{v.emoji} {v.label}
                </button>
              ))}
            </div>
          </div>
          <div style={crmCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>📊 Sammendrag</h3>
            {[['Aktiviteter',acts.length],['Kontakter',cts.length],['Dokumenter',docs.length],['Åpne oppgaver',openTasks.length],['Tilbud',linkedQuotes.length],['Fakturaer',linkedInvoices.length]].map(([k,v],i)=>(
              <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid #f8fafc', fontSize:'13px' }}>
                <span style={{ color:'#94a3b8' }}>{k}</span><span style={{ fontWeight:'700', color:'#0f172a' }}>{v}</span>
              </div>
            ))}
          </div>
          <div style={crmCard}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'10px' }}>
              <h3 style={{ margin:0, fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>⚡ Rask handling</h3>
            </div>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {[['📞 Logg samtale','call'],['🤝 Logg møte','meeting'],['📧 Logg e-post','email'],['✅ Legg til oppgave','task'],['📝 Skriv notat','note']].map(([l,type])=>(
                <button key={type} onClick={()=>setShowNewActivity({defaultType:type})}
                  style={{ padding:'9px 14px', border:'1px solid #f1f5f9', borderRadius:'10px', background:'#f8fafc', cursor:'pointer', fontSize:'13px', textAlign:'left', fontWeight:'500', color:'#475569' }}
                  onMouseEnter={e=>{e.currentTarget.style.background='#f0fdf4';e.currentTarget.style.color='#059669'}} onMouseLeave={e=>{e.currentTarget.style.background='#f8fafc';e.currentTarget.style.color='#475569'}}>{l}</button>
              ))}
            </div>
          </div>
        </div>
      </div>

      {editing&&<CRMEditorModal user={user} initial={c} onClose={()=>setEditing(false)} onSaved={()=>{setEditing(false);refresh()}} />}
      {showNewContact&&<ContactModal customerId={c.id} onClose={()=>setShowNewContact(false)} onSaved={()=>{setShowNewContact(false);loadDetails()}} />}
      {showNewActivity&&<ActivityModal customerId={c.id} defaultType={typeof showNewActivity==='object'?showNewActivity.defaultType:'note'} user={user} onClose={()=>setShowNewActivity(false)} onSaved={()=>{setShowNewActivity(false);loadDetails()}} />}
      {showQuotePicker&&<QuotePickerModal quotes={quotes} customer={c} onClose={()=>setShowQuotePicker(false)} onLink={linkQuote} />}
    </div>
  )
}

function CRMEditorModal({ user, initial, onClose, onSaved }) {
  const isEdit=!!initial
  const [form, setForm] = useState({ name:initial?.name||'', type:initial?.type||'lead', status:initial?.status||'lead', orgnr:initial?.orgnr||'', industry:initial?.industry||'', email:initial?.email||'', phone:initial?.phone||'', website:initial?.website||'', address:initial?.address||'', postal:initial?.postal||'', city:initial?.city||'', estimated_value:initial?.estimated_value||'', notes:initial?.notes||'' })
  const [saving, setSaving] = useState(false)
  const set=(k,v)=>setForm(f=>({...f,[k]:v}))
  const lbl=t=><label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'6px' }}>{t}</label>

  const handleSave = async () => {
    if (!form.name.trim()) return alert('Navn er påkrevd')
    setSaving(true)
    try {
      const payload={...form,estimated_value:form.estimated_value?parseFloat(form.estimated_value):null,updated_at:new Date().toISOString()}
      if (isEdit) { const {error}=await supabase.from('crm_customers').update(payload).eq('id',initial.id); if(error) throw error }
      else { const {error}=await supabase.from('crm_customers').insert({...payload,created_by:user?.id}); if(error) throw error }
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed',inset:0,zIndex:100,display:'flex',alignItems:'center',justifyContent:'center',padding:'16px' }}>
      <div style={{ position:'absolute',inset:0,background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative',background:'white',borderRadius:'20px',width:'100%',maxWidth:'640px',maxHeight:'92vh',display:'flex',flexDirection:'column',boxShadow:'0 20px 60px rgba(0,0,0,0.2)',fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding:'18px 24px',borderBottom:'1px solid #f1f5f9',display:'flex',justifyContent:'space-between',alignItems:'center',flexShrink:0 }}>
          <h2 style={{ margin:0,fontSize:'18px',fontWeight:'700',color:'#0f172a' }}>🤝 {isEdit?'Rediger':'Ny'} kunde / lead</h2>
          <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
            <button type="button" onClick={onClose} style={{ padding:'8px 16px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleSave} disabled={saving} style={{ padding:'8px 20px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize:'14px', fontWeight:'700' }}>{saving?'Lagrer...':isEdit?'Lagre':'Opprett'}</button>
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8', marginLeft:'4px' }}>×</button>
          </div>
        </div>
        <div style={{ overflowY:'auto',flex:1,padding:'20px 24px',display:'grid',gridTemplateColumns:'1fr 1fr',gap:'12px' }}>
          <div style={{ gridColumn:'1/-1' }}>
            <label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'8px' }}>Type</label>
            <div style={{ display:'flex',gap:'8px' }}>
              {Object.entries(CRM_TYPE).map(([k,v])=>(
                <button key={k} onClick={()=>set('type',k)} style={{ flex:1,padding:'8px',borderRadius:'10px',border:`2px solid ${form.type===k?'#059669':'#e2e8f0'}`,background:form.type===k?'#f0fdf4':'white',cursor:'pointer',fontWeight:form.type===k?'700':'500',fontSize:'13px',color:form.type===k?'#059669':'#64748b' }}>
                  {v.emoji} {v.label}
                </button>
              ))}
            </div>
          </div>
          <div style={{ gridColumn:'1/-1' }}>{lbl('Navn *')}<input value={form.name} onChange={e=>set('name',e.target.value)} placeholder="Firma- eller personnavn" style={crmInp} /></div>
          <div>{lbl('Status')}<select value={form.status} onChange={e=>set('status',e.target.value)} style={crmInp}>{Object.entries(CRM_STATUS).map(([k,v])=><option key={k} value={k}>{v.emoji} {v.label}</option>)}</select></div>
          <div>{lbl('Bransje')}<select value={form.industry} onChange={e=>set('industry',e.target.value)} style={crmInp}><option value="">Velg...</option>{INDUSTRIES.map(i=><option key={i} value={i}>{i}</option>)}</select></div>
          <div>{lbl('Org.nr')}<input value={form.orgnr} onChange={e=>set('orgnr',e.target.value)} placeholder="123 456 789" style={crmInp} /></div>
          <div>{lbl('Estimert verdi (kr)')}<input type="number" value={form.estimated_value} onChange={e=>set('estimated_value',e.target.value)} placeholder="0" style={crmInp} /></div>
          <div>{lbl('E-post')}<input type="email" value={form.email} onChange={e=>set('email',e.target.value)} placeholder="kontakt@firma.no" style={crmInp} /></div>
          <div>{lbl('Telefon')}<input value={form.phone} onChange={e=>set('phone',e.target.value)} placeholder="+47 xxx xx xxx" style={crmInp} /></div>
          <div style={{ gridColumn:'1/-1' }}>{lbl('Nettside')}<input value={form.website} onChange={e=>set('website',e.target.value)} placeholder="https://www.firma.no" style={crmInp} /></div>
          <div style={{ gridColumn:'1/-1' }}>{lbl('Adresse')}<input value={form.address} onChange={e=>set('address',e.target.value)} placeholder="Gateadresse" style={crmInp} /></div>
          <div>{lbl('Postnr')}<input value={form.postal} onChange={e=>set('postal',e.target.value)} placeholder="0000" style={crmInp} /></div>
          <div>{lbl('By')}<input value={form.city} onChange={e=>set('city',e.target.value)} placeholder="By" style={crmInp} /></div>
          <div style={{ gridColumn:'1/-1' }}>{lbl('Notater')}<textarea value={form.notes} onChange={e=>set('notes',e.target.value)} rows={3} placeholder="Interne notater..." style={{ ...crmInp,resize:'none' }} /></div>
        </div>

      </div>
    </div>
  )
}

